questions.answer:
```go
package cgoa

// #include <stdint.h>
// #include <stdlib.h>
// extern int start_work(const uint8_t* in, size_t in_len, uint8_t** out, size_t* out_len);
// extern const char* last_error(void);
// extern void free_error(char* err);
import "C"
import (
	"fmt"
	"runtime"
	"sync"
	"unsafe"
)

func DoWork(in []byte) ([]byte, error) {
	runtime.LockOSThread()
	defer runtime.UnlockOSThread()

	var out *C.uint8_t
	var outLen C.size_t

	inPtr := (*C.uint8_t)(unsafe.Pointer(&in[0]))
	inLen := C.size_t(len(in))

	result := C.start_work(inPtr, inLen, &out, &outLen)

	if result != 0 {
		errC := C.last_error()
		if errC != nil {
			errMsg := C.GoString(errC)
			C.free_error(errC)
			return nil, fmt.Errorf("C error: %s", errMsg)
		}
		return nil, fmt.Errorf("unknown error: %d", result)
	}

	outSlice := C.GoBytes(unsafe.Pointer(out), C.int(outLen))
	C.free(unsafe.Pointer(out))

	return outSlice, nil
}
```

```go
func ExampleDoWork_concurrent() {
	in1 := []byte("input1")
	in2 := []byte("input2")

	var wg sync.WaitGroup
	wg.Add(2)

	go func() {
		defer wg.Done()
		out, err := DoWork(in1)
		if err != nil {
			fmt.Printf("goroutine 1 error: %v\n", err)
			return
		}
		fmt.Printf("goroutine 1 result: %s\n", out)
	}()

	go func() {
		defer wg.Done()
		out, err := DoWork(in2)
		if err != nil {
			fmt.Printf("goroutine 2 error: %v\n", err)
			return
		}
		fmt.Printf("goroutine 2 result: %s\n", out)
	}()

	wg.Wait()
}
```

questions.explanation:
## Why This Is Asked
Tests designing a real-world CGO callback bridge with per‑operation context and concurrency.

## Key Concepts
- CGO callbacks require Go-exported functions and careful memory ownership for C strings
- Per-operation context mapping with a mutex-protected map
- Correct error propagation and resource cleanup for multiple concurrent operations

## Code Example

```c
// header.h
typedef void (*cb_t)(int status, const char* payload, void* ctx);
void start_operation(int op_id, cb_t cb, void* ctx);
```

```c
// minimal.c
#include <stdlib.h>
#include <pthread.h>

typedef void (*cb_t)(int, const char*, void*);

struct op_ctx { int op_id; cb_t cb; void* ctx; };

static void* worker(void* arg){
  struct op_ctx* oc = (struct op_ctx*)arg;
  const char* payload = "ok";
  oc->cb(0, payload, oc->ctx);
  free(oc);
  return NULL;
}

void start_operation(int op_id, cb_t cb, void* ctx){
  pthread_t t;
  struct op_ctx* oc = (struct op_ctx*)malloc(sizeof(struct op_ctx));
  oc->op_id = op_id;
  oc->cb = cb;
  oc->ctx = ctx;
  pthread_create(&t, NULL, worker, oc);
  pthread_detach(t);
}
```

```go
// binding.go
package main

/*
#include "header.h"

extern void goCallback(int status, const char* payload, void* ctx);
static void cgoCallback(int status, const char* payload, void* ctx){
  goCallback(status, payload, ctx);
}
*/
import "C"
import (
  "sync"
  "unsafe"
  "fmt"
)

type opHandle struct{ ch chan string; err chan error }

var (
  mu sync.Mutex
  handlers = make(map[unsafe.Pointer]*opHandle)
)

//export goCallback
func goCallback(status C.int, payload *C.char, ctx unsafe.Pointer){
  mu.Lock()
  h := handlers[ctx]
  delete(handlers, ctx)
  mu.Unlock()
  if status == 0 {
    h.ch <- C.GoString(payload)
  } else {
    h.err <- fmt.Errorf("C error %d", int(status))
  }
}

func StartOperation(opID int) (<-chan string, <-chan error){
  h := &opHandle{ch: make(chan string, 1), err: make(chan error, 1)}
  ctx := unsafe.Pointer(h)
  mu.Lock()
  handlers[ctx] = h
  mu.Unlock()
  C.start_operation(C.int(opID), (C.cb_t)(C.cgoCallback), ctx)
  return h.ch, h.err
}
```

```go
// main.go
package main
import "fmt"

func main(){
  ch1, err1 := StartOperation(1)
  ch2, err2 := StartOperation(2)
  select {
  case p := <-ch1:
    fmt.Println("op1:", p)
  case e := <-err1:
    fmt.Println("op1 err:", e)
  }
  select {
  case p := <-ch2:
    fmt.Println("op2:", p)
  case e := <-err2:
    fmt.Println("op2 err:", e)
  }
}
```

## Follow-up Questions
- How would you safely shut down in-flight operations and drain channels on shutdown?
- How to integrate with CGO thread-safety guarantees and prevent deadlocks when Go GC runs?

