```go
// ds_bindings.go
package ds

/*
#include "ds.h"
#include <stdlib.h>
*/
import "C"
import (
  "errors"
  "runtime"
)

type DataSourceHandle struct { p *C.DataSource }

func OpenDataSource(path string) (*DataSourceHandle, error) {
  cpath := C.CString(path)
  defer C.free(unsafe.Pointer(cpath))
  var perish C.int
  h := C.ds_open(cpath, &perish)
  if h == nil {
    if perish != 0 {
      return nil, errors.New("failed to open data source")
    }
    return nil, errors.New("unknown error")
  }
  ds := &DataSourceHandle{p: h}
  runtime.SetFinalizer(ds, func(d *DataSourceHandle) { d.Close() })
  return ds, nil
}

func (d *DataSourceHandle) Next() (float64, error) {
  var out C.double
  var errmsg *C.char
  code := C.ds_next(d.p, &out, &errmsg)
  if code != 0 {
    defer func() { if errmsg != nil { C.free(unsafe.Pointer(errmsg)) } }()
    if errmsg != nil {
      s := C.GoString(errmsg)
      return 0, errors.New(s)
    }
    return 0, errors.New("ds_next failed")
  }
  return float64(out), nil
}

func (d *DataSourceHandle) Close() error {
  if d.p != nil {
    C.ds_close(d.p)
    d.p = nil
  }
  return nil
}
```

