questions.explanation:
## Why This Is Asked
Tests ability to map C streaming callbacks to Go channels, memory ownership across CGO boundaries, and robust cancellation in concurrent workloads.

## Key Concepts
- CGO memory ownership across callback boundaries
- Bridging C callbacks to Go channels with safe copying
- Per-call cancellation and resource lifecycle management
- Concurrency isolation for multiple streams

## Code Example
```go
// Pseudo CGO binding sketch (Go)
package main
/*
#include <stdlib.h>
#include <stdint.h>
typedef void (*chunk_cb)(const uint8_t* chunk, size_t len, void* user);
void stream_process(const uint8_t* data, size_t len, chunk_cb cb, void* user);
*/
import "C"

func ProcessStream(in []byte) (<-chan []byte, func(), error) {
    ch := make(chan []byte)
    done := make(chan struct{})

    // C callback that copies chunks to Go channel
    cb := func(chunk *C.uint8_t, len C.size_t, user unsafe.Pointer) {
        goSlice := C.GoBytes(unsafe.Pointer(chunk), C.int(len))
        select {
        case ch <- goSlice:
        case <-done:
        }
    }

    // Start processing and return cancellation
    go func() {
        C.stream_process((*C.uint8_t)(&in[0]), C.size_t(len(in)), 
                        (*C.chunk_cb)(unsafe.Pointer(&cb)), nil)
        close(ch)
    }()

    cancel := func() { close(done); /* free C resources */ }
    return ch, cancel, nil
}
```

