```c
// counter.c (stub with mutex)
#include <stdlib.h>
#include <pthread.h>
typedef struct AtomicCounter {
  int val;
  pthread_mutex_t m;
} AtomicCounter;
AtomicCounter* ac_new(void){ AtomicCounter* a = malloc(sizeof(AtomicCounter)); a->val=0; pthread_mutex_init(&a->m, NULL); return a; }
void ac_inc(AtomicCounter* a){ pthread_mutex_lock(&a->m); a->val++; pthread_mutex_unlock(&a->m); }
int ac_get(AtomicCounter* a){ pthread_mutex_lock(&a->m); int v=a->val; pthread_mutex_unlock(&a->m); return v; }
void ac_free(AtomicCounter* a){ pthread_mutex_destroy(&a->m); free(a); }
