// C header (reverse_string.h)
size_t reverse_string(const char* input, char* output, size_t max_len);
```
```javascript
// Minimal C implementation (reverse_string.c)
#include <string.h>
#include <stddef.h>

size_t reverse_string(const char* input, char* output, size_t max_len) {
  size_t len = strlen(input);
  if (len >= max_len) len = max_len - 1;
  for (size_t i = 0; i < len; ++i) {
    output[i] = input[len - 1 - i];
  }
  output[len] = '\0';
  return len;
}
```
