)

func ReverseGo(s string) (string, error) {
  in := C.CString(s)
  defer C.free(unsafe.Pointer(in))
  buf := make([]byte, len(s)+1)
  written := C.reverse_string(in, (*C.char)(unsafe.Pointer(&buf[0])), C.size_t(len(buf)))
  if int(written) < 0 {
    return "", fmt.Errorf("reverse failed")
  }
  return string(buf[:written]), nil
}
