## Code Example

**stream_encrypt.h**
```c
#ifndef STREAM_ENCRYPT_H
#define STREAM_ENCRYPT_H

#include <stddef.h>
#include <stdint.h>

typedef void (*chunk_cb)(const uint8_t* out, size_t out_len, int status, void* ctx);

int stream_encrypt(const uint8_t* in, size_t in_len, chunk_cb cb, void* ctx);

#endif
```

**stream_encrypt.c**
```c
#include "stream_encrypt.h"
#include <stdlib.h>
#include <string.h>

#define BLOCK_SIZE 4096

static void encrypt_block(const uint8_t* in, size_t len, uint8_t** out, size_t* out_len) {
    *out = (uint8_t*)malloc(len);
    memcpy(*out, in, len);
    *out_len = len;
}

int stream_encrypt(const uint8_t* in, size_t in_len, chunk_cb cb, void* ctx) {
    size_t offset = 0;
    while (offset < in_len) {
        size_t block_len = (offset + BLOCK_SIZE > in_len) ? (in_len - offset) : BLOCK_SIZE;
        uint8_t* encrypted = NULL;
        size_t encrypted_len = 0;

        encrypt_block(in + offset, block_len, &encrypted, &encrypted_len);
        cb(encrypted, encrypted_len, 0, ctx);
        free(encrypted);

        offset += block_len;
    }
    return 0;
}
```

**stream_encrypt.go**
```go
package main

/*
#include "stream_encrypt.h"
#include <stdlib.h>

static int call_stream_encrypt(const uint8_t* in, size_t in_len, void* ctx) {
    return stream_encrypt(in, in_len, NULL, ctx);
}
*/
import "C"

import (
    "fmt"
    "sync"
    "unsafe"
)

type StreamResult struct {
    Data []byte
    Err  error
}

var workerPool = make(chan struct{}, 4)

//export chunkCallback
func chunkCallback(out *C.uint8_t, outLen C.size_t, status C.int, ctx unsafe.Pointer) {
    result := (*chan StreamResult)(ctx)
    data := C.GoBytes(unsafe.Pointer(out), C.int(outLen))
    if status != 0 {
        *result <- StreamResult{Err: fmt.Errorf("encryption error: %d", status)}
    } else {
        *result <- StreamResult{Data: data}
    }
}

func StartEncryptStream(input string, key []byte) (<-chan []byte, <-chan error) {
    chunks := make(chan []byte, 10)
    errs := make(chan error, 10)
    resultChan := make(chan StreamResult)

    go func() {
        defer close(chunks)
        defer close(errs)

        workerPool <- struct{}{}
        defer func() { <-workerPool }()

        cInput := C.CString(input)
        defer C.free(unsafe.Pointer(cInput))

        C.stream_encrypt(
            (*C.uint8_t)(unsafe.Pointer(cInput)),
            C.size_t(len(input)),
            (C.chunk_cb)(C.chunkCallback),
            unsafe.Pointer(&resultChan),
        )

        close(resultChan)
    }()

    go func() {
        for result := range resultChan {
            if result.Err != nil {
                errs <- result.Err
            } else {
                chunks <- result.Data
            }
        }
    }()

    return chunks, errs
}

func main() {
    var wg sync.WaitGroup

    for i := 0; i < 2; i++ {
        wg.Add(1)
        go func(id int) {
            defer wg.Done()
            chunks, errs := StartEncryptStream(fmt.Sprintf("message-%d", id), []byte("key"))
            for {
                select {
                case chunk, ok := <-chunks:
                    if !ok {
                        return
                    }
                    fmt.Printf("Stream %d: got chunk len=%d\n", id, len(chunk))
                case err, ok := <-errs:
                    if !ok {
                        return
                    }
                    fmt.Printf("Stream %d: error: %v\n", id, err)
                }
            }
        }(i)
    }

    wg.Wait()
}
```

