// binding.go
package main
/*
#include "header.h"
#include <stdlib.h>
*/
import "C"
import (
  "errors"
  "runtime"
  "sync"
  "unsafe"
)

type Session struct{ p *C.Session; mu sync.Mutex }

func CreateSession(config string) (*Session, error) {
  cg := C.CString(config)
  defer C.free(unsafe.Pointer(cg))
  s := C.create_session(cg)
  if s == nil {
    return nil, errors.New("failed to create session")
  }
  sess := &Session{p: s}
  runtime.SetFinalizer(sess, func(ss *Session){ ss.Close() })
  return sess, nil
}

func (s *Session) AnalyzeBatch(batch []string) (string, error) {
  s.mu.Lock()
  defer s.mu.Unlock()
  // build C array of strings
  n := len(batch)
  cstrs := make([]*C.char, n)
  for i, b := range batch {
    c := C.CString(b)
    cstrs[i] = c
  }
  defer func() { for _, c := range cstrs { if c != nil { C.free(unsafe.Pointer(c)) } } }()
  var inputs **C.char
  if n > 0 {
    inputs = &cstrs[0]
  } else { inputs = nil }
  res := C.analyze_batch(s.p, inputs, C.size_t(n))
  if res == nil { return "", errors.New("analyze_batch failed") }
  defer C.free(unsafe.Pointer(res))
  goStr := C.GoString(res)
  return goStr, nil
}

func (s *Session) Close() {
  if s.p != nil {
    C.destroy_session(s.p)
    s.p = nil
  }
}
