```go
// Go binding
package kvstore

// #include "kv_store.h"
// #include <stdlib.h>
import "C"
import (
    "errors"
    "sync"
    "unsafe"
)

type KVStore struct {
    handle unsafe.Pointer
    mu     sync.RWMutex
}

func OpenKV(path string) (*KVStore, error) {
    var handle *C.void
    cPath := C.CString(path)
    defer C.free(unsafe.Pointer(cPath))

    ret := C.kv_store_open(cPath, &handle)
    if ret != 0 {
        return nil, errors.New("failed to open KV store")
    }
    return &KVStore{handle: handle}, nil
}

func (k *KVStore) Put(key, value string) error {
    k.mu.Lock()
    defer k.mu.Unlock()

    cKey := C.CString(key)
    cValue := C.CString(value)
    defer C.free(unsafe.Pointer(cKey))
    defer C.free(unsafe.Pointer(cValue))

    ret := C.kv_store_put(k.handle, cKey, cValue)
    if ret != 0 {
        return errors.New("failed to put value")
    }
    return nil
}

func (k *KVStore) Get(key string) (string, error) {
    k.mu.RLock()
    defer k.mu.RUnlock()

    cKey := C.CString(key)
    defer C.free(unsafe.Pointer(cKey))

    var outValue *C.char
    ret := C.kv_store_get(k.handle, cKey, &outValue)
    if ret != 0 {
        return "", errors.New("failed to get value")
    }
    defer C.free(unsafe.Pointer(outValue))

    return C.GoString(outValue), nil
}

func (k *KVStore) Close() error {
    k.mu.Lock()
    defer k.mu.Unlock()

    ret := C.kv_store_close(k.handle)
    k.handle = nil
    if ret != 0 {
        return errors.New("failed to close KV store")
    }
    return nil
}
```

```go
// Worker pool for batch processing
type Operation struct {
    Key   string
    Value string
    Op    string // "put" or "get"
}

type WorkerPool struct {
    workers  int
    store    *KVStore
    jobs     chan Operation
    results  chan string
    wg       sync.WaitGroup
}

func NewWorkerPool(store *KVStore, workers int) *WorkerPool {
    return &WorkerPool{
        store:   store,
        workers: workers,
        jobs:    make(chan Operation, 1000),
        results: make(chan string, 1000),
    }
}

func (wp *WorkerPool) Start() {
    for i := 0; i < wp.workers; i++ {
        wp.wg.Add(1)
        go func() {
            defer wp.wg.Done()
            for op := range wp.jobs {
                var result string
                var err error
                switch op.Op {
                case "put":
                    err = wp.store.Put(op.Key, op.Value)
                case "get":
                    result, err = wp.store.Get(op.Key)
                }
                if err == nil {
                    wp.results <- result
                }
            }
        }()
    }
}

func (wp *WorkerPool) Submit(op Operation) {
    wp.jobs <- op
}

func (wp *WorkerPool) Close() {
    close(wp.jobs)
    wp.wg.Wait()
    close(wp.results)
}
```

## Critical Considerations
- **Memory Ownership**: Go allocates C strings via C.CString() and must explicitly free them. C allocates out_value_json via malloc, so Go must call C.free() to prevent leaks.
- **Thread-Safety**: The mutex protects all CGO calls, as C libraries are typically not thread-safe by default.
- **Error Handling**: C error codes (non-zero returns) are translated to Go errors for idiomatic error handling.

