void render_flags_json(const int* flags, size_t n, char* out, size_t max_len, int* err) {
  if (max_len == 0 || !out) { if (err) *err = 1; return; }
  size_t pos = 0;
  if (out) out[0] = '['; pos = 1;
  for (size_t i = 0; i < n; ++i) {
    const char* s = flags[i] ? "true" : "false";
    size_t len = strlen(s);
    if (pos + len + (i+1 < n ? 1 : 0) + 1 > max_len) { if (err) *err = 1; if (out) out[0] = '\0'; return; }
    if (out) memcpy(out + pos, s, len);
    pos += len;
    if (i + 1 < n) { if (out) out[pos] = ','; pos++; }
  }
  if (out) out[pos] = ']'; pos++;
  if (out) out[pos] = '\0';
  if (err) *err = 0;
}
