```c
// tlv_parser.c
#include <stdlib.h>
#include <string.h>
#include <stdio.h>
#include "tlv_parser.h"

static uint8_t rolling_checksum(const uint8_t* data, size_t len) {
    uint8_t sum = 0;
    for (size_t i = 0; i < len; i++) {
        sum = (sum << 1) | (sum >> 7);
        sum ^= data[i];
    }
    return sum;
}

char* parse_tlvs(const uint8_t* data, size_t length) {
    if (!data || length < 4) return NULL;

    size_t offset = 0;
    size_t capacity = 256;
    char* json = malloc(capacity);
    if (!json) return NULL;

    int pos = snprintf(json, capacity, "[{\n");

    while (offset + 4 <= length) {
        uint16_t tlv_type = (data[offset] << 8) | data[offset + 1];
        uint16_t tlv_len = (data[offset + 2] << 8) | data[offset + 3];

        if (offset + 4 + tlv_len > length) break;

        uint8_t checksum = rolling_checksum(data + offset + 4, tlv_len);

        char entry[128];
        int len = snprintf(entry, sizeof(entry),
            "  {\"type\": %d, \"length\": %d, \"checksum\": %d}%s\n",
            tlv_type, tlv_len, checksum,
            (offset + 4 + tlv_len < length) ? "," : "");

        if (pos + len >= (int)capacity) {
            capacity *= 2;
            json = realloc(json, capacity);
        }
        pos += snprintf(json + pos, capacity - pos, "%s", entry);
        offset += 4 + tlv_len;
    }

    snprintf(json + pos, capacity - pos, "}]");
    return json;
}

void free_json(char* json) {
    free(json);
}
```

