// hist.c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include "hist.h"

#define BUCKET_COUNT 10

static void compute_histogram(const double* data, size_t n, int* buckets) {
    memset(buckets, 0, BUCKET_COUNT * sizeof(int));
    if (n == 0) return;

    double min = data[0], max = data[0];
    for (size_t i = 1; i < n; i++) {
        if (data[i] < min) min = data[i];
        if (data[i] > max) max = data[i];
    }

    double range = max - min;
    if (range == 0) range = 1.0;

    for (size_t i = 0; i < n; i++) {
        int bucket = (int)((data[i] - min) / range * (BUCKET_COUNT - 1));
        if (bucket >= BUCKET_COUNT) bucket = BUCKET_COUNT - 1;
        buckets[bucket]++;
    }
}

int histogram_batch(const double* data, size_t n, char** out_json) {
    if (!data || !out_json) return -1;

    int buckets[BUCKET_COUNT];
    compute_histogram(data, n, buckets);

    size_t json_size = 256 + BUCKET_COUNT * 64;
    char* json = (char*)malloc(json_size);
    if (!json) return -1;

    snprintf(json, json_size, "{\"count\":%zu,\"buckets\":[", n);
    size_t pos = strlen(json);

    for (int i = 0; i < BUCKET_COUNT; i++) {
        int written = snprintf(json + pos, json_size - pos, 
            "%s%d", (i > 0 ? "," : ""), buckets[i]);
        pos += written;
    }

    snprintf(json + pos, json_size - pos, "]}");
    *out_json = json;
    return 0;
}
