func ComputeHistogramBatch(nums []float64) (string, error) {
	if len(nums) == 0 {
		return "", fmt.Errorf("empty input slice")
	}

	var jsonPtr *C.char
	n := C.size_t(len(nums))

	cNums := (*C.double)(unsafe.Pointer(&nums[0]))

	result := C.go_histogram_batch(cNums, n, &jsonPtr)
	if result != 0 {
		return "", fmt.Errorf("histogram_batch failed with code %d", result)
	}

	jsonStr := C.GoString(jsonPtr)
	C.free(unsafe.Pointer(jsonPtr))

	runtime.KeepAlive(nums)

	return jsonStr, nil
}
