### sort_strings.c
```c
#include "header.h"
#include <stdlib.h>
#include <string.h>

static void swap(char** a, char** b) {
    char* tmp = *a;
    *a = *b;
    *b = tmp;
}

int sort_strings(char** in_out, size_t n, 
    int (*cmp)(const char*, const char*, void*), 
    void* ctx) {
    if (!in_out || n == 0 || !cmp) return -1;

    for (size_t i = 0; i < n - 1; i++) {
        for (size_t j = 0; j < n - i - 1; j++) {
            int result = cmp(in_out[j], in_out[j + 1], ctx);
            if (result > 0) {
                swap(&in_out[j], &in_out[j + 1]);
            }
        }
    }
    return 0;
}
```

### sort_wrapper.go
```go
package main

/*
#include "header.h"
#include <stdlib.h>

typedef int (*CmpFn)(const char*, const char*, void*);

static int wrapper_cmp(const char* a, const char* b, void* ctx) {
    // This is a placeholder; actual invocation happens via CGO
    return 0;
}
*/
import "C"
import (
	"fmt"
	"runtime"
	"sync"
	"unsafe"
)

type sortHandle C.int

var handleStore = struct {
	sync.RWMutex
	m map[sortHandle]func(string, string) int
}{
m: make(map[sortHandle]func(string, string) int)}

//export goCmpCallback
func goCmpCallback(a, b *C.char, ctx unsafe.Pointer) C.int {
	handle := sortHandle(uintptr(ctx))
	handleStore.RLock()
	cmpFn := handleStore.m[handle]
	handleStore.RUnlock()

	if cmpFn == nil {
		return 0
	}
	return C.int(cmpFn(C.GoString(a), C.GoString(b)))
}

func SortStringsWithComparator(vals []string, cmp func(string, string) int) ([]string, error) {
	if cmp == nil {
		return nil, fmt.Errorf("comparator cannot be nil")
	}

	handle := sortHandle(runtime.NewCString("")) // dummy allocation for unique handle
	handleStore.Lock()
	handleStore.m[handle] = cmp
	handleStore.Unlock()

	cStrs := make([]*C.char, len(vals))
	for i, v := range vals {
		cStrs[i] = C.CString(v)
	}

	result := C.sort_strings(&cStrs[0], C.size_t(len(cStrs)),
		(C.CmpFn)(C.wrapper_cmp), unsafe.Pointer(uintptr(handle)))

	for i := range cStrs {
		C.free(unsafe.Pointer(cStrs[i]))
	}

	handleStore.Lock()
	delete(handleStore.m, handle)
	handleStore.Unlock()

	if result != 0 {
		return nil, fmt.Errorf("sort failed with code %d", result)
	}

	resultVals := make([]string, len(vals))
	for i, cs := range cStrs {
		resultVals[i] = C.GoString(cs)
	}
	return resultVals, nil
}
