	results   chan []string
	errors    chan error
	wg        sync.WaitGroup
}

func NewWorkerPool(workers int, bufSize int) *WorkerPool {
	return &WorkerPool{
		workers: workers,
		jobs:    make(chan Job, bufSize),
		results: make(chan []string, bufSize),
		errors:  make(chan error, bufSize),
	}
}

func (p *WorkerPool) Start(ctx context.Context, cmp func(string, string) int) {
	for i := 0; i < p.workers; i++ {
		p.wg.Add(1)
		go p.worker(ctx, cmp)
	}
}

func (p *WorkerPool) worker(ctx context.Context, cmp func(string, string) int) {
	defer p.wg.Done()
	for {
		select {
		case <-ctx.Done():
			return
		case job, ok := <-p.jobs:
			if !ok {
				return
			}
			result, err := SortStringsWithComparator(job.Input, cmp)
			if err != nil {
				p.errors <- err
			} else {
				p.results <- result
			}
		}
	}
}

func (p *WorkerPool) Submit(job Job) {
	p.jobs <- job
}

func (p *WorkerPool) Close() {
	close(p.jobs)
	p.wg.Wait()
	close(p.results)
	close(p.errors)
}
```

