## Why This Is Asked
This question tests CGO cross-language callback design, memory ownership semantics, and thread-safety under streaming workloads.

## Key Concepts
- **CGO callbacks and pointer safety**: Go pointers cannot be passed directly to C; doing so violates CGO safety rules and causes undefined behavior.
- **Registry pattern**: Use a map keyed by uintptr to manage context across the language boundary, avoiding direct Go pointer exposure to C.
- **Memory ownership**: Each JSON chunk must be copied by Go and freed by C—clearly define who owns what to prevent leaks or use-after-free bugs.
- **Concurrency safety**: Employ locking mechanisms and per-call context isolation to safely handle concurrent streaming operations.
- **Error propagation**: Route errors from C back to Go through the context object, ensuring failures are communicated reliably.

## Code Example
```c
// C header
typedef struct {
    void (*cb)(const char* json, size_t len, void* ctx);
    void* ctx;
} StreamContext;

void register_stream(int n, const char** items, void (*cb)(const char* json, size_t len, void* ctx), void* ctx);
```

```go
// Go implementation
package main

/*
#include <stdlib.h>
typedef struct {
    void (*cb)(const char*, size_t, void*);
    void* ctx;
} StreamContext;

extern void register_stream(int n, char** items, void (*cb)(const char*, size_t, void*), void* ctx);
*/
import "C"

import (
    "fmt"
    "sync"
    "unsafe"
)

var (
    contextRegistry = make(map[uintptr]*CallContext)
    registryMu      sync.RWMutex
)

type CallContext struct {
    ResultChan chan string
    ErrorChan  chan error
    Once       sync.Once
}

export func streamCallback(json *C.char, length C.size_t, ctx unsafe.Pointer) {
    registryMu.RLock()
    callCtx, ok := contextRegistry[uintptr(ctx)]
    registryMu.RUnlock()

    if !ok {
        return
    }

    goBytes := C.GoBytes(unsafe.Pointer(json), C.int(length))
    jsonStr := string(goBytes)

    callCtx.Once.Do(func() {
        close(callCtx.ResultChan)
        close(callCtx.ErrorChan)
    })

    select {
    case callCtx.ResultChan <- jsonStr:
    default:
    }

    C.free(unsafe.Pointer(json))
}

func StartStream(items []string, batchSize int) (<-chan string, <-chan error) {
    resultChan := make(chan string, batchSize)
    errorChan := make(chan error, 1)

    callCtx := &CallContext{
        ResultChan: resultChan,
        ErrorChan:  errorChan,
    }

    ctxKey := uintptr(unsafe.Pointer(&callCtx))

    registryMu.Lock()
    contextRegistry[ctxKey] = callCtx
    registryMu.Unlock()

    cItems := make([]*C.char, len(items))
    for i, item := range items {
        cItems[i] = C.CString(item)
    }
    defer func() {
        for _, cItem := range cItems {
            C.free(unsafe.Pointer(cItem))
        }
    }()

    C.register_stream(
        C.int(len(cItems)),
        (**C.char)(unsafe.Pointer(&cItems[0])),
        (unsafe.Pointer)(C.streamCallback),
        unsafe.Pointer(ctxKey),
    )

    return resultChan, errorChan
}
```

