/* C header and implementation */
typedef struct Node { const char* value; struct Node* next; } Node;

Node* build_list(const char** items, size_t n) {
    Node* head = NULL;
    Node* tail = NULL;
    for (size_t i = 0; i < n; i++) {
        Node* node = malloc(sizeof(Node));
        node->value = strdup(items[i]);
        node->next = NULL;
        if (tail) tail->next = node;
        else head = node;
        tail = node;
    }
    return head;
}

void free_list(Node* head) {
    while (head) {
        Node* next = head->next;
        free((void*)head->value);
        free(head);
        head = next;
    }
}
```

