// block_hasher.h
#ifndef BLOCK_HASHER_H
#define BLOCK_HASHER_H

#include <stddef.h>
#include <stdint.h>

typedef struct {
    int idx;
    size_t size;
    uint8_t hash[32];
} BlockInfo;

char* compute_block_hashes(const uint8_t* blocks[], const size_t* sizes, size_t count);
