```c
// block_hasher.c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>
#include "block_hasher.h"
#include <sha256.h> // assume SHA-256 implementation

char* compute_block_hashes(const uint8_t* blocks[], const size_t* sizes, size_t count) {
    BlockInfo* infos = malloc(count * sizeof(BlockInfo));
    if (!infos) return NULL;

    SHA256_CTX rolling_ctx;
    sha256_init(&rolling_ctx);

    for (size_t i = 0; i < count; i++) {
        infos[i].idx = (int)i;
        infos[i].size = sizes[i];
        sha256_update(&rolling_ctx, blocks[i], sizes[i]);
        sha256_final_block(blocks[i], sizes[i], infos[i].hash);
    }

    uint8_t final_hash[32];
    sha256_final(&rolling_ctx, final_hash);

    // Build JSON output
    size_t json_size = 256 + count * 128;
    char* json = malloc(json_size);
    if (!json) { free(infos); return NULL; }

    int offset = 0;
    offset += snprintf(json + offset, json_size - offset,
        "{\"blocks\":[");

    for (size_t i = 0; i < count; i++) {
        char hash_hex[65];
        for (int j = 0; j < 32; j++)
            sprintf(hash_hex + j*2, "%02x", infos[i].hash[j]);

        offset += snprintf(json + offset, json_size - offset,
            "%s{\"idx\":%d,\"size\":%zu,\"hash\":\"%s\"}",
            i > 0 ? "," : "", infos[i].idx, infos[i].size, hash_hex);
    }

    char final_hash_hex[65];
    for (int j = 0; j < 32; j++)
        sprintf(final_hash_hex + j*2, "%02x", final_hash[j]);

    size_t total = 0;
    for (size_t i = 0; i < count; i++) total += sizes[i];

    snprintf(json + offset, json_size - offset,
        "],\"rolling_hash\":\"%s\",\"total_bytes\":%zu}",
        final_hash_hex, total);

    free(infos);
    return json;
}

void free_json_string(char* json) {
    free(json);
}
```

