func StreamBlockHashes(blocks [][]byte) (string, error) {
    if len(blocks) == 0 {
        return "{\"blocks\":[],\"rolling_hash\":\"e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855\",\"total_bytes\":0}", nil
    }

    cBlocks := make([]*C.uint8_t, len(blocks))
    cSizes := make([]C.size_t, len(blocks))

    for i, b := range blocks {
        cBlocks[i] = (*C.uint8_t)(unsafe.Pointer(&b[0]))
        cSizes[i] = C.size_t(len(b))
    }

    result := C.compute_block_hashes(&cBlocks[0], &cSizes[0], C.size_t(len(blocks)))
    if result == nil {
        return "", errors.New("C computation failed")
    }
    defer C.free_json_string(result)

