```go
// main.go
package main

import (
    "encoding/hex"
    "errors"
    "fmt"
    "sync"
)

const numWorkers = 4

func main() {
    blocks := [][]byte{
        []byte("hello "),
        []byte("world\n"),
        []byte("test data for streaming"),
    }

    result, err := processBlocks(blocks)
    if err != nil {
        fmt.Fprintf(os.Stderr, "Error: %v\n", err)
        os.Exit(1)
    }
    fmt.Println(result)
}

func processBlocks(blocks [][]byte) (string, error) {
    if len(blocks) == 0 {
        return StreamBlockHashes(nil)
    }

    type job struct {
        idx   int
        data  []byte
    }
    type result struct {
        idx    int
        hash   [32]byte
        size   int
        err    error
    }

    jobs := make(chan job, len(blocks))
    results := make(chan result, len(blocks))

    var wg sync.WaitGroup
    for i := 0; i < numWorkers; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for j := range jobs {
                hash := sha256.Sum256(j.data)
                results <- result{
                    idx:  j.idx,
                    hash: hash,
                    size: len(j.data),
                }
            }
        }()
    }

    for i, b := range blocks {
        jobs <- job{idx: i, data: b}
    }
    close(jobs)

    go func() {
        wg.Wait()
        close(results)
    }()

    blockResults := make([]result, len(blocks))
    for r := range results {
        if r.err != nil {
            return "", r.err
        }
        blockResults[r.idx] = r
    }

    // Compute rolling hash
    var rolling [32]byte
    first := true
    for i := 0; i < len(blocks); i++ {
        br := blockResults[i]
        if first {
            rolling = br.hash
            first = false
        } else {
            combined := append(rolling[:], br.hash[:]...)
            rolling = sha256.Sum256(combined)
        }
    }

    // Build JSON
    json := "{\"blocks\":["
    total := 0
    for i, br := range blockResults {
        if i > 0 {
            json += ","
        }
        json += fmt.Sprintf("{\"idx\":%d,\"size\":%d,\"hash\":\"%s\"}",
            br.idx, br.size, hex.EncodeToString(br.hash[:]))
        total += br.size
    }
    json += fmt.Sprintf("],\"rolling_hash\":\"%s\",\"total_bytes\":%d}",
        hex.EncodeToString(rolling[:]), total)

    return json, nil
}
```

