type streamContext struct {
    dataCh  chan string
    errCh   chan error
    mu      sync.Mutex
    active  bool
}

//export csvCallback
func csvCallback(json *C.char, length C.size_t, status C.int, ctx unsafe.Pointer) {
    sc := (*streamContext)(ctx)
    sc.mu.Lock()
    defer sc.mu.Unlock()

    if !sc.active {
        return
    }

    if status != 0 {
        sc.errCh <- fmt.Errorf("stream error: status=%d", status)
        return
    }

    if json == nil {
        close(sc.dataCh)
        sc.active = false
        return
    }

    goStr := C.GoStringN(json, C.int(length))
    C.free(unsafe.Pointer(json))
    sc.dataCh <- goStr
}

func StartCSVStream(path string) (<-chan string, <-chan error) {
    dataCh := make(chan string, 10)
    errCh := make(chan error, 1)

    ctx := &streamContext{
        dataCh: dataCh,
        errCh:  errCh,
        active: true,
    }

    go func() {
        cPath := C.CString(path)
        defer C.free(unsafe.Pointer(cPath))

        C.csv_stream(cPath, C.csv_stream_callback(C.csvCallback), unsafe.Pointer(ctx))

        ctx.mu.Lock()
        if ctx.active {
            close(errCh)
        }
        ctx.mu.Unlock()
    }()

    return dataCh, errCh
}

func main() {
    dataCh1, errCh1 := StartCSVStream("file1.csv")
    dataCh2, errCh2 := StartCSVStream("file2.csv")

