## Solution: CGO Wrapper for Streaming C API

This solution demonstrates how to use CGO to bind a C streaming API with callback-based data delivery. The Go binding converts the C callback into a Go function, routing each malloc-allocated JSON result through a channel. Memory ownership follows a clear lifecycle: C allocates via malloc, Go consumes via the channel, then releases using C.free.

## Implementation

### 1) C Header and Implementation

**stream.h:**
```c
#ifndef STREAM_H
#define STREAM_H
#include <stdint.h>
#include <stddef.h>

typedef void (*stream_callback)(const char* json, size_t json_len, void* user);

void start_stream(const uint8_t* block, size_t len, stream_callback cb, void* user);
void free_json(char* json);

#endif
```

**stream.c:**
```c
#include "stream.h"
#include <stdlib.h>
#include <string.h>

static stream_callback g_cb;
static void* g_user;

void start_stream(const uint8_t* block, size_t len, stream_callback cb, void* user) {
    g_cb = cb;
    g_user = user;

    char* json = malloc(256);
    snprintf(json, 256, "{\"block_len\": %zu, \"status\": \"ok\"}", len);

    g_cb(json, strlen(json), g_user);
}

void free_json(char* json) {
    free(json);
}
```

### 2) Go Binding

**stream.go:**
```go
package stream

// #include "stream.h"
import "C"

import (
    "runtime/cgo"
    "unsafe"
)

type Result struct {
    JSON   string
    JSONPtr *C.char
}

type Stream struct {
    results chan Result
    errChan chan error
    done    chan struct{}
}

func (s *Stream) StreamResults() <-chan string {
    return s.results
}

//export stream_callback_go
func stream_callback_go(json *C.char, json_len C.size_t, user unsafe.Pointer) {
    handle := cgo.Handle(user)
    s := handle.Value().(*Stream)

    result := Result{
        JSON:   C.GoStringN(json, C.int(json_len)),
        JSONPtr: json,
    }
    s.results <- result
}

func StreamBlocks(blocks [][]byte) (<-chan string, error) {
    s := &Stream{
        results: make(chan Result, 100),
        errChan: make(chan error, 1),
        done:    make(chan struct{}),
    }

    handle := cgo.NewHandle(s)

    go func() {
        defer close(s.results)
        defer handle.Delete()

        for _, block := range blocks {
            C.start_stream(
                (*C.uchar)(&block[0]),
                C.size_t(len(block)),
                C.stream_callback(C.stream_callback_go),
                unsafe.Pointer(handle),
            )
        }
    }()

    results := make(chan string, 100)
    go func() {
        defer close(results)
        for r := range s.results {
            results <- r.JSON
            C.free_json(r.JSONPtr)
        }
    }()

    return results, nil
}
```

### 3) Worker Pool Implementation

**main.go:**
```go
package main

import (
    "fmt"
    "sync"
)

func main() {
    blocks := [][]byte{
        []byte("block1"),
        []byte("block2"),
        []byte("block3"),
    }

    const workers = 3
    blockChan := make(chan []byte, len(blocks))
    resultChan := make(chan string, 100)
    errChan := make(chan error, 1)

    var wg sync.WaitGroup

    for i := 0; i < workers; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for block := range blockChan {
                results, err := StreamBlocks([][]byte{block})
                if err != nil {
                    errChan <- err
                    return
                }
                for r := range results {
                    resultChan <- r
                }
            }
        }()
    }

    go func() {
        for _, b := range blocks {
            blockChan <- b
        }
        close(blockChan)
    }()

    go func() {
        wg.Wait()
        close(resultChan)
    }()

    for r := range resultChan {
        fmt.Println("Result:", r)
    }

    select {
    case err := <-errChan:
        fmt.Println("Error:", err)
    default:
    }
}
```

## Key Design Points

- **Memory Ownership**: C allocates JSON via malloc; Go explicitly frees via C.free()
- **CGO Handle**: cgo.NewHandle prevents garbage collection of Go struct during C callback
- **Worker Pool**: Enables parallel block processing
- **Channels**: Provide safe result communication between goroutines

