// utf8.c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int validate_utf8(const uint8_t* data, size_t len, char** errorMsg) {
    *errorMsg = NULL;

    for (size_t i = 0; i < len; i++) {
        if (data[i] <= 0x7F) continue;

        int bytes = 0;
        if ((data[i] & 0xE0) == 0xC0) bytes = 2;
        else if ((data[i] & 0xF0) == 0xE0) bytes = 3;
        else if ((data[i] & 0xF8) == 0xF0) bytes = 4;
        else {
            *errorMsg = malloc(64);
            snprintf(*errorMsg, 64, "Invalid UTF-8 start byte 0x%02X at position %zu", data[i], i);
            return -1;
        }

        if (i + bytes > len) {
            *errorMsg = malloc(64);
            snprintf(*errorMsg, 64, "Truncated UTF-8 sequence at position %zu", i);
            return -1;
        }

        for (int j = 1; j < bytes; j++) {
            if ((data[i + j] & 0xC0) != 0x80) {
                *errorMsg = malloc(64);
                snprintf(*errorMsg, 64, "Invalid continuation byte 0x%02X at position %zu", data[i + j], i + j);
                return -1;
            }
        }
        i += bytes - 1;
    }
    return 0;
}
```

