Design a CGO wrapper for a C library using an opaque handle lifecycle with the following API:

**C API:**
```c
rng_handle* rng_create(unsigned int seed);
int rng_add_data(rng_handle* h, const double* data, size_t n);
int rng_finalize(rng_handle* h, char** out_json);
void rng_destroy(rng_handle* h);
```

**Go Binding:**
```go
type Gen struct { h C.rng_handle }
func New(seed uint32) (*Gen, error)
func (g *Gen) Add(data []float64) error
func (g *Gen) Finalize() (string, error)
func (g *Gen) Destroy()
```

**Implementation:**

```go
package rng

// #include <stdlib.h>
// typedef struct rng_handle rng_handle;
// extern rng_handle* rng_create(unsigned int seed);
// extern int rng_add_data(rng_handle* h, const double* data, size_t n);
// extern int rng_finalize(rng_handle* h, char** out_json);
// extern void rng_destroy(rng_handle* h);
import "C"
import "unsafe"

type Gen struct {
    h C.rng_handle
}

func New(seed uint32) (*Gen, error) {
    h := C.rng_create(C.uint(seed))
    if h == nil {
        return nil, errors.New("failed to create RNG")
    }
    return &Gen{h: h}, nil
}

func (g *Gen) Add(data []float64) error {
    if len(data) == 0 {
        return nil
    }
    cData := (*C.double)(C.malloc(C.size_t(len(data)) * C.sizeof_double))
    defer C.free(unsafe.Pointer(cData))

    slice := (*[1 << 30]float64)(unsafe.Pointer(cData))[:len(data):len(data)]
    copy(slice, data)

    res := C.rng_add_data(g.h, cData, C.size_t(len(data)))
    if res != 0 {
        return errors.New("failed to add data")
    }
    return nil
}

func (g *Gen) Finalize() (string, error) {
    var json *C.char
    res := C.rng_finalize(g.h, &json)
    if res != 0 {
        return "", errors.New("failed to finalize")
    }
    defer C.free(unsafe.Pointer(json))
    return C.GoString(json), nil
}

func (g *Gen) Destroy() {
    if g.h != nil {
        C.rng_destroy(g.h)
        g.h = nil
    }
}
```

