if err != nil {
    log.Fatal(err)
}
defer gen.Destroy()

if err := gen.Add([]float64{1.0, 2.0, 3.0}); err != nil {
    log.Fatal(err)
}

json, err := gen.Finalize()
fmt.Println(json)
```

