```go
// processor.go
package processor

/*
#include <stdlib.h>
#include "processor.h"

//export goResultCallback
static void goResultCallback(int block_id, int status, char* error_msg, void* user_data) {
    // Bridge to Go callback - user_data contains (*CallbackBridge)
}
*/
import "C"
import (
    "context"
    "runtime"
    "sync"
    "unsafe"
)

type Result struct {
    BlockID  int
    Status   int
    ErrorMsg string
}

type CallbackBridge struct {
    Results chan Result
    Done    chan struct{}
}

//export goResultCallback
func goResultCallback(blockID C.int, status C.int, errMsg *C.char, userData unsafe.Pointer) {
    bridge := (*CallbackBridge)(userData)
    var errStr string
    if errMsg != nil {
        errStr = C.GoString(errMsg)
    }
    select {
    case bridge.Results <- Result{BlockID: int(blockID), Status: int(status), ErrorMsg: errStr}:
    case <-bridge.Done:
    }
}

// ProcessBlocksAsync processes blocks asynchronously via C thread pool.
//
// Memory ownership:
//   - Go passes block slices to C (C copies or references, Go retains ownership)
//   - C returns JSON via malloc'd pointer; caller must call freeJsonResult
//   - Callbacks execute on C thread pool; result channel is thread-safe
//
// Cancellation:
//   - Cancels via context; C-side cancellation is requested but not guaranteed
func ProcessBlocksAsync(ctx context.Context, blocks [][]byte) (string, error) {
    if len(blocks) == 0 {
        return "[]", nil
    }

    bridge := &CallbackBridge{
        Results: make(chan Result, len(blocks)),
        Done:    make(chan struct{}),
    }
    defer close(bridge.Done)

    // Prepare C arrays
    cBlocks := make([]*C.uint8_t, len(blocks))
    cSizes := make([]C.size_t, len(blocks))

    for i, b := range blocks {
        cBlocks[i] = (*C.uint8_t)(unsafe.Pointer(&b[0]))
        cSizes[i] = C.size_t(len(b))
    }

    // Start worker pool to consume results
    var wg sync.WaitGroup
    resultChan := make(chan Result, len(blocks))

    workerCount := 4
    for i := 0; i < workerCount; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for {
                select {
                case r, ok := <-bridge.Results:
                    if !ok {
                        return
                    }
                    resultChan <- r
                case <-ctx.Done():
                    return
                }
            }
        }()
    }

    // Call C async processing
    cJSON := C.process_blocks_async(
        (**C.uint8_t)(unsafe.Pointer(&cBlocks[0])),
        (*C.size_t)(unsafe.Pointer(&cSizes[0])),
        C.size_t(len(blocks)),
        (C.result_callback)(C.goResultCallback),
        unsafe.Pointer(bridge),
    )

    if cJSON == nil {
        close(bridge.Done)
        wg.Wait()
        close(resultChan)
        return "", nil
    }

    // Wait for results or context cancellation
    results := make([]Result, 0, len(blocks))
    collected := 0

    for collected < len(blocks) {
        select {
        case r := <-resultChan:
            results = append(results, r)
            collected++
        case <-ctx.Done():
            C.request_cancellation(nil)
            break
        }
    }

    close(bridge.Done)
    wg.Wait()
    close(resultChan)

    jsonStr := C.GoString(cJSON)
    C.free_json_result(cJSON)

    // Sort results by BlockID for consistent ordering
    // ... (sort implementation)

    return jsonStr, nil
}
```

