## CGO Wrapper for C Streaming API with Callback-Driven Design

### C Header and Implementation

```c
// stream_processor.h
#ifndef STREAM_PROCESSOR_H
#define STREAM_PROCESSOR_H

#include <stdlib.h>

typedef struct {
    char* buffer;
    size_t capacity;
    size_t len;
} OutputBuffer;

typedef struct {
    OutputBuffer output;
    void* user_data;
} StreamContext;

int start_stream_processor(const void* data_chunk, size_t chunk_len,
    void (*cb)(const char* out, size_t out_len, void* user), void* user);

int finish_stream_processor(void* user);

#endif
```

```c
// stream_processor.c
#include <string.h>
#include "stream_processor.h"

static void default_callback(const char* out, size_t out_len, void* user) {
    StreamContext* ctx = (StreamContext*)user;
    if (!ctx || !out || out_len == 0) return;

    if (ctx->output.buffer == NULL) {
        ctx->output.capacity = 4096;
        ctx->output.buffer = malloc(ctx->output.capacity);
        if (!ctx->output.buffer) return;
    }

    if (ctx->output.len + out_len > ctx->output.capacity) {
        ctx->output.capacity *= 2;
        char* new_buf = realloc(ctx->output.buffer, ctx->output.capacity);
        if (!new_buf) return;
        ctx->output.buffer = new_buf;
    }

    memcpy(ctx->output.buffer + ctx->output.len, out, out_len);
    ctx->output.len += out_len;
}

int start_stream_processor(const void* data_chunk, size_t chunk_len,
    void (*cb)(const char* out, size_t out_len, void* user), void* user) {
    if (!data_chunk || !cb || !user) return -1;
    cb((const char*)data_chunk, chunk_len, user);
    return 0;
}

int finish_stream_processor(void* user) {
    if (!user) return -1;
    return 0;
}
```

### Go Binding

```go
package stream

// #include <stdlib.h>
// #include "stream_processor.h"
import "C"
import (
    "errors"
    "sync"
    "unsafe"
)

type StreamContext struct {
    outputBuffer []byte
    mu           sync.Mutex
    err          error
}

//export goCallback
func goCallback(out *C.char, outLen C.size_t, user unsafe.Pointer) {
    ctx := (*StreamContext)(user)
    ctx.mu.Lock()
    defer ctx.mu.Unlock()

    if outLen > 0 {
        ctx.outputBuffer = append(ctx.outputBuffer,
            C.GoBytes(unsafe.Pointer(out), C.int(outLen))...)
    }
}

func StreamProcess(chunks [][]byte) (string, error) {
    ctx := &StreamContext{}
    ctxPtr := unsafe.Pointer(ctx)

    for _, chunk := range chunks {
        if len(chunk) == 0 {
            continue
        }

        cChunk := (*C.void)(unsafe.Pointer(&chunk[0]))
        cLen := C.size_t(len(chunk))

        ret := C.start_stream_processor(cChunk, cLen, C.goCallback, ctxPtr)
        if ret != 0 {
            return "", errors.New("stream processing failed")
        }
    }

    if ret := C.finish_stream_processor(ctxPtr); ret != 0 {
        return "", errors.New("stream finish failed")
    }

    ctx.mu.Lock()
    defer ctx.mu.Unlock()

    return string(ctx.outputBuffer), ctx.err
}
```

### Go Program with Worker Pool

```go
package main

import (
    "encoding/json"
    "errors"
    "sync"
    "sync/atomic"
    "unsafe"
)

type Result struct {
    Output string
    Error  error
}

type StreamProcessor struct {
    workers  int
    ctx      *StreamContext
    results  chan Result
    wg       sync.WaitGroup
    errCount int32
}

func NewStreamProcessor(workers int) *StreamProcessor {
    return &StreamProcessor{
        workers: workers,
        results: make(chan Result, workers),
    }
}

func (sp *StreamProcessor) ProcessChunkPool(chunks [][]byte) (string, error) {
    sp.ctx = &StreamContext{}

    sp.wg.Add(sp.workers)
    for i := 0; i < sp.workers; i++ {
        go sp.worker(i, chunks)
    }

    go func() {
        sp.wg.Wait()
        close(sp.results)
    }()

    var outputs []string
    for result := range sp.results {
        if result.Error != nil {
            return "", result.Error
        }
        outputs = append(outputs, result.Output)
    }

    combined := combineOutputs(outputs)
    jsonResult, err := json.Marshal(combined)
    if err != nil {
        return "", err
    }

    return string(jsonResult), nil
}

func (sp *StreamProcessor) worker(id int, chunks [][]byte) {
    defer sp.wg.Done()

    chunkStart := id * len(chunks) / sp.workers
    chunkEnd := (id + 1) * len(chunks) / sp.workers

    if chunkStart >= len(chunks) {
        return
    }

    localChunks := chunks[chunkStart:chunkEnd]

    output, err := StreamProcess(localChunks)
    if err != nil {
        atomic.AddInt32(&sp.errCount, 1)
        sp.results <- Result{Error: err}
        return
    }

    sp.results <- Result{Output: output}
}

func combineOutputs(outputs []string) string {
    var result string
    for _, o := range outputs {
        result += o
    }
    return result
}

func main() {
    chunks := [][]byte{
        []byte(`{"data":`),
        []byte(`"chunk1"`),
        []byte(`,"chunk2"`),
        []byte(`}`),
    }

    sp := NewStreamProcessor(4)
    result, err := sp.ProcessChunkPool(chunks)
    if err != nil {
        panic(err)
    }

    println("Result:", result)
}
```

**Key Design Points:**
- C owns callback execution; Go manages output buffer through context pointer
- Memory: C allocates/reallocates output buffer; Go receives a copy on finish
- Worker pool distributes chunks across goroutines with result aggregation
- `unsafe.Pointer` bridges CGO memory boundaries safely

