```c
// file.c
#include "file.h"
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

const char* read_text_file(const char* path, int* err) {
    *err = 0;
    FILE* f = fopen(path, "rb");
    if (!f) {
        *err = 1; // Not found
        return NULL;
    }

    fseek(f, 0, SEEK_END);
    long len = ftell(f);
    fseek(f, 0, SEEK_SET);

    char* buf = malloc(len + 1);
    if (!buf) {
        *err = 3;
        fclose(f);
        return NULL;
    }

    fread(buf, 1, len, f);
    buf[len] = '\0';
    fclose(f);
    return buf;
}
