        case 2:
            return "", fmt.Errorf("permission denied: %s", path)
        default:
            return "", errors.New("unknown error")
        }
    }

    goStr := C.GoString(result)
    C.free(unsafe.Pointer(result))
    return goStr, nil
}

func main() {
    var wg sync.WaitGroup

    for _, path := range []string{"file1.txt", "file2.txt"} {
