questions.explanation:
Why This Is Asked
- Tests CGO memory ownership, cross-language error handling, and basic concurrency.
- Ensures a candidate designs clean API boundaries between C and Go.

Key Concepts
- Memory ownership across CGO calls and explicit free paths.
- Thread-safety in C via mutex and in Go via goroutines.
- Minimal C header/implementation and Go bindings with proper error propagation.

Code Example
```javascript
// kv.h (C header)
void kv_put(const char* key, const char* value);
const char* kv_get(const char* key);
void kv_free_result(const char* ptr);
```
```javascript
// kv.c (C impl, minimal, thread-safe)
#include <pthread.h>
#include <stdlib.h>
#include <string.h>
#include "kv.h"

static pthread_mutex_t mtx = PTHREAD_MUTEX_INITIALIZER;
// Very small in-memory store as a linked list for simplicity
typedef struct Node { char* key; char* value; struct Node* next; } Node;
static Node* head = NULL;

static void insert_or_update(const char* k, const char* v) {
  Node* cur = head;
  while (cur) {
    if (strcmp(cur->key, k) == 0) { free(cur->value); cur->value = strdup(v); return; }
    cur = cur->next;
  }
  Node* n = malloc(sizeof(Node));
  n->key = strdup(k);
  n->value = strdup(v);
  n->next = head;
  head = n;
}

void kv_put(const char* key, const char* value) {
  pthread_mutex_lock(&mtx);
  insert_or_update(key, value);
  pthread_mutex_unlock(&mtx);
}

const char* kv_get(const char* key) {
  pthread_mutex_lock(&mtx);
  Node* cur = head;
  while (cur) {
    if (strcmp(cur->key, key) == 0) {
      char* ret = malloc(strlen(cur->value) + 1);
      strcpy(ret, cur->value);
      pthread_mutex_unlock(&mtx);
      return ret;
    }
    cur = cur->next;
  }
  pthread_mutex_unlock(&mtx);
  return NULL;
}

void kv_free_result(const char* ptr) { free((void*)ptr); }
