This question tests your ability to bridge Go and C using CGO, manage memory across the FFI boundary, and coordinate concurrency between Go routines and C callbacks.

## Solution

### 1) C Header and Minimal Implementation

```c
// hash_stream.h
#ifndef HASH_STREAM_H
#define HASH_STREAM_H

#include <stddef.h>

char* compute_hash_stream(
    const void* data,
    size_t len,
    void (*progress)(size_t processed, size_t total, void* ctx),
    void* ctx
);

#endif
```

```c
// hash_stream.c
#include <stdlib.h>
#include <string.h>
#include "hash_stream.h"

char* compute_hash_stream(const void* data, size_t len, void (*progress)(size_t, size_t, void*), void* ctx) {
    const char* input = (const char*)data;
    size_t chunk_size = len / 10;
    if (chunk_size == 0) chunk_size = 1;

    for (size_t i = 0; i < len; i += chunk_size) {
        size_t processed = (i + chunk_size < len) ? i + chunk_size : len;
        if (progress) {
            progress(processed, len, ctx);
        }
    }

    char* result = malloc(65);
    snprintf(result, 65, "dummy_hash_for_%zu_bytes", len);
    return result;
}
```

### 2) Go Binding with CGO

```go
// hash_go.go
package main

/*
#include <stdlib.h>
#include "hash_stream.h"

// Declaration needed for CGO to compile
extern void goProgressCallback(size_t processed, size_t total, void* ctx);
*/
import "C"
import (
	"fmt"
	"sync"
	"unsafe"
)

type progressCallback struct {
	mu       sync.Mutex
	progress uint64
	total    uint64
	done     chan struct{}
}

var callbackMap = &sync.Map{}
var nextHandle uint64

//export goProgressCallback
func goProgressCallback(processed, total C.size_t, ctx unsafe.Pointer) {
	handle := *(*uint64)(ctx)
	if cb, ok := callbackMap.Load(handle); ok {
		p := cb.(*progressCallback)
		p.mu.Lock()
		p.progress = uint64(processed)
		p.total = uint64(total)
		p.mu.Unlock()
	}
}

func ComputeHashChunks(chunks [][]byte) (string, error) {
	var totalLen C.size_t
	for _, chunk := range chunks {
		totalLen += C.size_t(len(chunk))
	}

	data := make([]byte, totalLen)
	offset := 0
	for _, chunk := range chunks {
		copy(data[offset:], chunk)
		offset += len(chunk)
	}

	cb := &progressCallback{
		done: make(chan struct{}),
	}
	handle := nextHandle
	nextHandle++
	callbackMap.Store(handle, cb)
	defer callbackMap.Delete(handle)

	result := C.compute_hash_stream(
		unsafe.Pointer(&data[0]),
		totalLen,
		C.progress(C.goProgressCallback),
		unsafe.Pointer(&handle),
	)

	if result == nil {
		return "", fmt.Errorf("hash computation failed")
	}
	defer C.free(unsafe.Pointer(result))

	return C.GoString(result), nil
}
```

### 3) Concurrent Go Program with Progress

```go
// main.go
package main

import (
	"fmt"
	"sync"
	"time"
)

func main() {
	chunks := [][]byte{
		make([]byte, 1000000),
		make([]byte, 1000000),
		make([]byte, 1000000),
	}

	var wg sync.WaitGroup
	resultChan := make(chan string, 1)
	errChan := make(chan error, 1)

	wg.Add(1)
	go func() {
		defer wg.Done()
		result, err := ComputeHashChunks(chunks)
		if err != nil {
			errChan <- err
			return
		}
		resultChan <- result
	}()

	go func() {
		wg.Wait()
		close(resultChan)
		close(errChan)
	}()

	select {
	case result := <-resultChan:
		fmt.Printf("Hash: %s\n", result)
	case err := <-errChan:
		fmt.Printf("Error: %v\n", err)
	}
}

func init() {
	time.Sleep(100 * time.Millisecond)
}
```

## Key Implementation Details

1. **CGO Callback Bridge**: Use `//export` to expose a Go function as a C callback. The callback must be registered in the same package that imports C.

2. **Context Handle Pattern**: Pass a handle (uint64) to C as the context, then map it back to the Go callback struct using a `sync.Map`.

3. **Memory Management**: The C function returns `malloc`-allocated memory, so use `C.free(unsafe.Pointer(result))` to prevent memory leaks.

4. **Concurrency**: Use a worker pool or goroutines to process chunks in parallel while keeping progress reporting visible through shared state protected by mutexes.

