## C Header (parser.h)

```c
#ifndef PARSER_H
#define PARSER_H

#include <stdint.h>
#include <stddef.h>

typedef struct Parser Parser;

typedef struct ParserConfig {
    int max_frame_size;
    int flags;
} ParserConfig;

Parser* parser_create(const ParserConfig* config);
int parser_feed(Parser* p, const uint8_t* data, size_t len);
int parser_flush(Parser* p, char** out_json);
void parser_destroy(Parser* p);

#endif
```

## C Implementation (parser.c)

```c
#include <stdlib.h>
#include <string.h>
#include "parser.h"

struct Parser {
    uint8_t* buffer;
    size_t buffer_size;
    size_t buffer_capacity;
    int max_frame_size;
    int flags;
    int state;
};

Parser* parser_create(const ParserConfig* config) {
    Parser* p = calloc(1, sizeof(Parser));
    if (!p) return NULL;

    if (config) {
        p->max_frame_size = config->max_frame_size;
        p->flags = config->flags;
    }
    p->buffer_capacity = p->max_frame_size > 0 ? p->max_frame_size : 4096;
    p->buffer = malloc(p->buffer_capacity);
    return p;
}

int parser_feed(Parser* p, const uint8_t* data, size_t len) {
    if (!p || !data || !len) return -1;

    if (p->buffer_size + len > p->buffer_capacity) {
        p->buffer_capacity *= 2;
        p->buffer = realloc(p->buffer, p->buffer_capacity);
    }
    memcpy(p->buffer + p->buffer_size, data, len);
    p->buffer_size += len;
    return 0;
}

int parser_flush(Parser* p, char** out_json) {
    if (!p || !out_json) return -1;

    if (p->buffer_size == 0) {
        *out_json = NULL;
        return 0;
    }

    // Simulate JSON output for complete frame
    char* json = malloc(256);
    snprintf(json, 256, "{\"data\": \"%.*s\", \"length\": %zu}", 
             (int)p->buffer_size, p->buffer, p->buffer_size);

    p->buffer_size = 0;
    *out_json = json;
    return 1; // 1 indicates complete frame available
}

void parser_destroy(Parser* p) {
    if (p) {
        free(p->buffer);
        free(p);
    }
}
```

## Go Binding (parser_go.go)

```go
package parser

/*
#cgo CFLAGS: -I.
#cgo LDFLAGS: -L. -lparser

#include <stdlib.h>
#include "parser.h"

extern int goParserFeed(Parser* p, const uint8_t* data, size_t len);
*/
import "C"
import (
	"context"
	"fmt"
	"sync"
	"unsafe"
)

type Parser struct {
	cptr     *C.Parser
	closed   bool
	mu       sync.Mutex
}

type ParserConfig struct {
	MaxFrameSize int
	Flags        int
}

func Create(config *ParserConfig) (*Parser, error) {
	var cConfig C.ParserConfig
	if config != nil {
		cConfig.max_frame_size = C.int(config.MaxFrameSize)
		cConfig.flags = C.int(config.Flags)
	}

	cptr := C.parser_create(&cConfig)
	if cptr == nil {
		return nil, fmt.Errorf("failed to create parser")
	}

	return &Parser{cptr: cptr}, nil
}

func (p *Parser) Destroy() {
	p.mu.Lock()
	defer p.mu.Unlock()

	if p.closed {
		return
	}
	p.closed = true
	C.parser_destroy(p.cptr)
}

func StreamParse(p *Parser, chunks <-chan []byte) (<-chan string, <-chan error) {
	outCh := make(chan string, 10)
	errCh := make(chan error, 1)

	go func() {
		defer close(outCh)
		defer close(errCh)

		for data := range chunks {
			if len(data) == 0 {
				continue
			}

			p.mu.Lock()
			if p.closed {
				p.mu.Unlock()
				errCh <- fmt.Errorf("parser closed")
				return
			}

			cData := (*C.uint8_t)(unsafe.Pointer(&data[0]))
			result := C.parser_feed(p.cptr, cData, C.size_t(len(data)))
			p.mu.Unlock()

			if result < 0 {
				errCh <- fmt.Errorf("feed error: %d", result)
				return
			}

			// Check for complete frames
			var jsonOut *C.char
			p.mu.Lock()
			flushResult := C.parser_flush(p.cptr, &jsonOut)
			p.mu.Unlock()

			if flushResult > 0 && jsonOut != nil {
				goStr := C.GoString(jsonOut)
				C.free(unsafe.Pointer(jsonOut))
				outCh <- goStr
			}
		}
	}()

	return outCh, errCh
}

func StreamParseWithContext(ctx context.Context, p *Parser, chunks <-chan []byte) (<-chan string, <-chan error) {
	outCh := make(chan string, 10)
	errCh := make(chan error, 1)

	go func() {
		defer close(outCh)
		defer close(errCh)

		for {
			select {
			case <-ctx.Done():
				errCh <- ctx.Err()
				return
			case data, ok := <-chunks:
				if !ok {
					return
				}

				if len(data) == 0 {
					continue
				}

				p.mu.Lock()
				if p.closed {
					p.mu.Unlock()
					errCh <- fmt.Errorf("parser closed")
					return
				}

				cData := (*C.uint8_t)(unsafe.Pointer(&data[0]))
				result := C.parser_feed(p.cptr, cData, C.size_t(len(data)))
				p.mu.Unlock()

				if result < 0 {
					errCh <- fmt.Errorf("feed error: %d", result)
					return
				}

				var jsonOut *C.char
				p.mu.Lock()
				flushResult := C.parser_flush(p.cptr, &jsonOut)
				p.mu.Unlock()

				if flushResult > 0 && jsonOut != nil {
					goStr := C.GoString(jsonOut)
					C.free(unsafe.Pointer(jsonOut))
					outCh <- goStr
				}
			}
		}
	}()

	return outCh, errCh
}
```

## Go Program with Streaming and Cancellation (main.go)

```go
package main

import (
	"context"
	"fmt"
	"os"
	"os/signal"
	"sync"
	"syscall"
	"time"

	"parser"
)

func main() {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	p, err := parser.Create(&parser.ParserConfig{
		MaxFrameSize: 1024,
		Flags:       0,
	})
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to create parser: %v\n", err)
		os.Exit(1)
	}
	defer p.Destroy()

	chunks := make(chan []byte, 10)

	var wg sync.WaitGroup

	// Producer: simulate streaming chunks
	wg.Add(1)
	go func() {
		defer wg.Done()
		defer close(chunks)

		// Simulate streaming binary data
		frames := [][]byte{
			[]byte("frame1_"),
			[]byte("data1"),
			[]byte("_more"),
			[]byte("frame2_"),
			[]byte("data2"),
		}

		for i, chunk := range frames {
			select {
			case <-ctx.Done():
				return
			case chunks <- chunk:
				fmt.Printf("Sent chunk %d: %q\n", i, string(chunk))
				time.Sleep(100 * time.Millisecond)
			}
		}
	}()

	// Consumer: process parsed JSON frames
	wg.Add(1)
	go func() {
		defer wg.Done()

		jsonCh, errCh := parser.StreamParseWithContext(ctx, p, chunks)

		for {
			select {
			case <-ctx.Done():
				return
			case jsonStr, ok := <-jsonCh:
				if !ok {
					return
				}
				fmt.Printf("Received JSON: %s\n", jsonStr)
			case err, ok := <-errCh:
				if !ok {
					return
				}
				fmt.Fprintf(os.Stderr, "Error: %v\n", err)
				cancel()
				return
			}
		}
	}()

	// Signal handler for graceful cancellation
	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	wg.Add(1)
	go func() {
		defer wg.Done()
		sig := <-sigCh
		fmt.Printf("\nReceived signal: %v\n", sig)
		cancel()
	}()

	wg.Wait()
	fmt.Println("Stream processing completed")
}
```

## Key Implementation Details

**Memory Ownership Transfer:**
- `parser_flush` returns a `malloc`-allocated C string via `char**` output parameter
- Go copies the string with `C.GoString()` and immediately frees the C memory with `C.free()`
- This prevents memory leaks from C-allocated buffers

**Thread Safety:**
- Mutex protects the Parser handle from concurrent access
- `Destroy()` is safe to call while streaming

**Cancellation:**
- `context.Context` propagates cancellation to the streaming pipeline
- `StreamParseWithContext` checks `ctx.Done()` before processing each chunk
- Signal handlers trigger graceful shutdown on SIGINT/SIGTERM

