import "C"
import (
    "errors"
    "runtime"
    "sync"
    "unsafe"
)

type StreamHandle struct {
    ptr *C.CSVParser
    mu  sync.RWMutex
}

func StartCSVStream(schema []string) (StreamHandle, error) {
    if len(schema) == 0 {
        return StreamHandle{}, errors.New("schema cannot be empty")
    }

    cSchema := make([]*C.char, len(schema))
    for i, s := range schema {
        cSchema[i] = C.CString(s)
    }
    defer func() {
        for _, cs := range cSchema {
            C.free(unsafe.Pointer(cs))
        }
    }()

    ptr := C.csv_parser_create(&cSchema[0], C.size_t(len(schema)))
    if ptr == nil {
        return StreamHandle{}, errors.New("failed to create parser")
    }

    handle := StreamHandle{ptr: ptr}
    runtime.SetFinalizer(&handle, func(h *StreamHandle) {
        h.mu.Lock()
        defer h.mu.Unlock()
        if h.ptr != nil {
            C.csv_parser_free(h.ptr)
            h.ptr = nil
        }
    })

    return handle, nil
}

func FeedChunk(handle StreamHandle, chunk []byte, isLast bool) (string, error) {
    handle.mu.RLock()
    defer handle.mu.RUnlock()

    if handle.ptr == nil {
        return "", errors.New("invalid stream handle")
    }

    var cChunk *C.char
    if len(chunk) > 0 {
        cChunk = C.CBytes(chunk)
        defer C.free(unsafe.Pointer(cChunk))
    }

    var cJson *C.char
    result := C.csv_parser_feed(
        handle.ptr,
        cChunk,
        C.size_t(len(chunk)),
        C.bool(isLast),
        &cJson,
    )

    if result < 0 {
        return "", errors.New("parsing error")
    }

    jsonStr := C.GoString(cJson)
    C.free(unsafe.Pointer(cJson))

    return jsonStr, nil
}
