type StreamHandler struct {
    ch     chan string
    done   chan struct{}
    mu     sync.Mutex
    handle C void
}

var handlers = make(map[*StreamHandler]struct{}{})
var handlersMu sync.RWMutex

//export chunkProxy
func chunkProxy(data *C.char, len C.size_t, user unsafe.Pointer) {
    handlersMu.RLock()
    defer handlersMu.RUnlock()

    handler := (*StreamHandler)(user)
    if handler == nil {
        return
    }

    chunk := C.GoStringN(data, C.int(len))

    select {
    case handler.ch <- chunk:
    default:
    }
}

func StartStream(source string) (chan string, error) {
    ch := make(chan string, 10)
    handler := &StreamHandler{
        ch:   ch,
        done: make(chan struct{}),
    }

    handlersMu.Lock()
    handlers[handler] = struct{}{}
    handlersMu.Unlock()

    cSource := C.CString(source)
    defer C.free(unsafe.Pointer(cSource))

    handle := C.go_start_stream(cSource, unsafe.Pointer(handler))
    handler.handle = handle

    return ch, nil
}

func StopStream(handler *StreamHandler) {
    handler.mu.Lock()
    defer handler.mu.Unlock()

    if handler.handle != nil {
        C.stop_stream(handler.handle)
        handler.handle = nil
    }

    close(handler.ch)

    handlersMu.Lock()
    delete(handlers, handler)
    handlersMu.Unlock()
}

func main() {
    ch, err := StartStream("source-123")
    if err != nil {
        panic(err)
    }

    var wg sync.WaitGroup
    wg.Add(1)

    go func() {
        defer wg.Done()
        dec := json.NewDecoder(ch)

        for {
            select {
            case <-ch:
                var data map[string]interface{}
                if err := dec.Decode(&data); err != nil {
                    fmt.Printf("Parse error: %v\n", err)
                    continue
                }
                fmt.Printf("Received: %v\n", data)
                runtime.Gosched()
            }
        }
    }()

    wg.Wait()
}
