import "C"
import (
    "fmt"
    "runtime/cgo"
    "unsafe"
)

type ChunkData struct {
    JSON     string
    Error    error
}

type StreamProcessor struct {
    resultChan chan ChunkData
    handle     cgo.Handle
}

func NewStreamProcessor() *StreamProcessor {
    return &StreamProcessor{
        resultChan: make(chan ChunkData, 1024),
    }
}

export func goChunkCallback(json *C.char, ctx unsafe.Pointer) {
    handle := *(*cgo.Handle)(ctx)
    sp := handle.Value().(*StreamProcessor)

    jsonStr := C.GoString(json)
    C.free(unsafe.Pointer(json))

    select {
    case sp.resultChan <- ChunkData{JSON: jsonStr}:
    default:
        // Handle backpressure
    }
}

func (sp *StreamProcessor) StreamProcess(data []byte) error {
    if len(data) == 0 {
        return fmt.Errorf("empty input data")
    }

    sp.handle = cgo.NewHandle(sp)
    defer sp.handle.Delete()

    C.start_streaming_wrapper(
        (*C.uchar)(&data[0]),
        C.size_t(len(data)),
        unsafe.Pointer(&sp.handle),
    )

    close(sp.resultChan)
    return nil
}

func (sp *StreamProcessor) Results() <-chan ChunkData {
    return sp.resultChan
}
