```go
// main.go
package main

import (
    "encoding/json"
    "errors"
    "fmt"
    "sync"
)

type Record struct {
    ID    int    `json:"id"`
    Value string `json:"value"`
}

type ChunkResult struct {
    Record Record
    Error  error
}

func main() {
    const numWorkers = 4
    const bufferSize = 100

    processor := NewStreamProcessor()
    inputChan := make(chan []byte, bufferSize)
    resultChan := make(chan ChunkResult, bufferSize)
    errChan := make(chan error, 1)

    var wg sync.WaitGroup

    // Worker pool
    for i := 0; i < numWorkers; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for chunk := range processor.Results() {
                if chunk.Error != nil {
                    select {
                    case errChan <- chunk.Error:
                    default:
                    }
                    continue
                }

                var record Record
                if err := json.Unmarshal([]byte(chunk.JSON), &record); err != nil {
                    resultChan <- ChunkResult{Error: err}
                    continue
                }

                resultChan <- ChunkResult{Record: record}
            }
        }()
    }

    // Simulated continuous data feed
    go func() {
        for i := 0; i < 10; i++ {
            inputChan <- []byte(fmt.Sprintf("data chunk %d", i))
        }
        close(inputChan)
    }()

    // Process streaming data
    go func() {
        for data := range inputChan {
            if err := processor.StreamProcess(data); err != nil {
                select {
                case errChan <- err:
                default:
                }
            }
        }
        wg.Wait()
        close(resultChan)
        close(errChan)
    }()

    // Collect results
    var errs []error
    for result := range resultChan {
        if result.Error != nil {
            errs = append(errs, result.Error)
            continue
        }
        fmt.Printf("Processed: %+v\n", result.Record)
    }

    if len(errs) > 0 {
        for _, err := range errs {
            fmt.Printf("Error: %v\n", err)
        }
    }

    select {
    case err := <-errChan:
        if err != nil {
            fmt.Printf("Stream error: %v\n", err)
        }
    default:
    }

    if len(errs) > 0 {
        errors.Join(errs...)
    }
}
