## Solution

### 1. C Header and Implementation

```c
// conv_batch.h
#ifndef CONV_BATCH_H
#define CONV_BATCH_H

#include <stddef.h>
#include <stdint.h>

#ifdef __cplusplus
extern "C" {
#endif

int apply_conv_batch(const uint8_t** images, size_t n, size_t h, size_t w,
                     const float* kernel, size_t ksize, char** out_json);

#ifdef __cplusplus
}
#endif

#endif
```

```c
// conv_batch.c
#include <stdlib.h>
#include <string.h>
#include <stdint.h>
#include <math.h>

static void compute_stats(const uint8_t* img, size_t h, size_t w, float* mean, float* stddev) {
    double sum = 0, sum_sq = 0;
    size_t count = h * w;

    for (size_t i = 0; i < count; i++) {
        sum += img[i];
        sum_sq += (double)img[i] * img[i];
    }

    *mean = (float)(sum / count);
    *stddev = (float)sqrt(sum_sq / count - (*mean) * (*mean));
}

static void crc32_update(uint32_t* crc, const char* str, size_t len) {
    for (size_t i = 0; i < len; i++) {
        *crc ^= (uint8_t)str[i];
        for (int b = 0; b < 8; b++) {
            *crc = (*crc & 1) ? (0xEDB88320 ^ (*crc >> 1)) : (*crc >> 1);
        }
    }
}

int apply_conv_batch(const uint8_t** images, size_t n, size_t h, size_t w,
                     const float* kernel, size_t ksize, char** out_json) {
    if (!images || !kernel || !out_json || n == 0 || h == 0 || w == 0 || ksize == 0) {
        return -1;
    }

    size_t json_cap = 256;
    char* json = malloc(json_cap);
    if (!json) return -1;
    json[0] = '\0';

    uint32_t crc = 0xFFFFFFFF;

    for (size_t i = 0; i < n; i++) {
        float mean, stddev;
        compute_stats(images[i], h, w, &mean, &stddev);

        int ok = (images[i] != NULL);
        char entry[256];
        snprintf(entry, sizeof(entry),
                 "{\"idx\": %zu, \"ok\": %s, \"stats\": {\"mean\": %.6f, \"stddev\": %.6f}}",
                 i, ok ? "true" : "false", mean, stddev);

        crc32_update(&crc, entry, strlen(entry));

        size_t entry_len = strlen(entry);
        size_t json_len = strlen(json);
        if (json_len + entry_len + 4 > json_cap) {
            json_cap *= 2;
            char* new_json = realloc(json, json_cap);
            if (!new_json) { free(json); return -1; }
            json = new_json;
        }

        if (i > 0) strcat(json, ", ");
        strcat(json, entry);
    }

    char crc_str[16];
    snprintf(crc_str, sizeof(crc_str), "%08X", ~crc);

    size_t final_size = strlen(json) + 64;
    char* final_json = malloc(final_size);
    if (!final_json) { free(json); return -1; }

    snprintf(final_json, final_size, "{\"results\": [%s], \"crc\": \"%s\"}",
             json, crc_str);
    free(json);

    *out_json = final_json;
    return 0;
}
```

### 2. Go Binding with Memory Ownership

```go
// conv_bind.go
package main

/*
#cgo CFLAGS: -O2
#cgo LDFLAGS: -L. -lconv_batch
#include <stdlib.h>
#include "conv_batch.h"
*/
import "C"

import (
    "errors"
    "fmt"
    "unsafe"
)

type ConvBatchResult struct {
    Index  int     `json:"idx"`
    OK     bool    `json:"ok"`
    Mean   float64 `json:"mean"`
    StdDev float64 `json:"stddev"`
}

type BatchResult struct {
    Results []ConvBatchResult `json:"results"`
    CRC     string            `json:"crc"`
}

func ApplyConvBatch(images [][]byte, kernel []float32) (string, error) {
    if len(images) == 0 {
        return "", errors.New("empty image batch")
    }

    h := len(images[0])
    w := len(images[0][:])
    n := len(images)

    cImages := make([]*C.uint8_t, n)
    for i, img := range images {
        if len(img) != h*w {
            return "", fmt.Errorf("image %d has invalid size: expected %d, got %d", i, h*w, len(img))
        }
        cImg := (*C.uint8_t)(C.malloc(C.size_t(len(img))))
        if cImg == nil {
            return "", errors.New("malloc failed for image buffer")
        }
        copy((*[1 << 30]byte)(unsafe.Pointer(cImg))[:len(img)], img)
        cImages[i] = cImg
    }
    defer func() {
        for _, p := range cImages {
            C.free(unsafe.Pointer(p))
        }
    }()

    cKernel := (*C.float)(C.malloc(C.size_t(len(kernel) * 4)))
    if cKernel == nil {
        return "", errors.New("malloc failed for kernel")
    }
    defer C.free(unsafe.Pointer(cKernel))
    copy((*[1 << 30]float32)(unsafe.Pointer(cKernel))[:len(kernel)], kernel)

    var cJson *C.char
    ret := C.apply_conv_batch((**C.uint8_t)(unsafe.Pointer(&cImages[0])),
        C.size_t(n), C.size_t(h), C.size_t(w),
        cKernel, C.size_t(len(kernel)), &cJson)

    if ret != 0 {
        return "", fmt.Errorf("C function returned error code: %d", ret)
    }
    if cJson == nil {
        return "", errors.New("null JSON returned from C")
    }

    result := C.GoString(cJson)
    C.free(unsafe.Pointer(cJson))

    return result, nil
}
```

### 3. Go Worker Pool Implementation

```go
// worker_pool.go
package main

import (
    "encoding/json"
    "errors"
    "fmt"
    "sync"
    "sync/atomic"
)

type WorkItem struct {
    ID     int
    Images [][]byte
    Kernel []float32
    Result chan Result
}

type Result struct {
    ID   int
    JSON string
    Err  error
}

type WorkerPool struct {
    workers int
    jobs    chan WorkItem
    wg      sync.WaitGroup
    errors  int64
}

func NewWorkerPool(workers int, queueSize int) *WorkerPool {
    return &WorkerPool{
        workers: workers,
        jobs:    make(chan WorkItem, queueSize),
    }
}

func (p *WorkerPool) Start() {
    for i := 0; i < p.workers; i++ {
        p.wg.Add(1)
        go p.worker()
    }
}

func (p *WorkerPool) worker() {
    defer p.wg.Done()
    for item := range p.jobs {
        jsonStr, err := ApplyConvBatch(item.Images, item.Kernel)
        item.Result <- Result{
            ID:   item.ID,
            JSON: jsonStr,
            Err:  err,
        }
    }
}

func (p *WorkerPool) Submit(item WorkItem) error {
    select {
    case p.jobs <- item:
        return nil
    default:
        return errors.New("worker pool queue full")
    }
}

func (p *WorkerPool) Shutdown() {
    close(p.jobs)
    p.wg.Wait()
}

func (p *WorkerPool) ErrorCount() int64 {
    return atomic.LoadInt64(&p.errors)
}

func main() {
    pool := NewWorkerPool(4, 100)
    pool.Start()

    kernel := []float32{0, -1, 0, -1, 5, -1, 0, -1, 0}

    for batchID := 0; batchID < 10; batchID++ {
        images := make([][]byte, 8)
        for i := range images {
            img := make([]byte, 256*256)
            for j := range img {
                img[j] = byte((i*j + batchID) % 256)
            }
            images[i] = img
        }

        resultCh := make(chan Result, 1)
        pool.Submit(WorkItem{
            ID:     batchID,
            Images: images,
            Kernel: kernel,
            Result: resultCh,
        })

        result := <-resultCh
        if result.Err != nil {
            fmt.Printf("Batch %d failed: %v\n", batchID, result.Err)
            atomic.AddInt64(&pool.errors, 1)
            continue
        }

        var parsed BatchResult
        if err := json.Unmarshal([]byte(result.JSON), &parsed); err != nil {
            fmt.Printf("Batch %d JSON parse error: %v\n", batchID, err)
            atomic.AddInt64(&pool.errors, 1)
            continue
        }

        okCount := 0
        for _, r := range parsed.Results {
            if r.OK {
                okCount++
            }
        }
        fmt.Printf("Batch %d: CRC=%s, OK=%d/%d\n",
            batchID, parsed.CRC, okCount, len(images))
    }

    pool.Shutdown()
    if pool.ErrorCount() > 0 {
        fmt.Printf("Pool completed with %d errors\n", pool.ErrorCount())
    }
}
```

