type resultCollector struct {
    results []TickResult
    mu      sync.Mutex
    done    chan struct{}
    err     error
}

func ProcessTicks(ticks []Tick) ([]TickResult, error) {
    if len(ticks) == 0 {
        return nil, nil
    }

    collector := &resultCollector{
        results: make([]TickResult, 0, len(ticks)),
        done:    make(chan struct{}),
    }

    // Convert Go slice to C array
    cTicks := (*C.tick)(unsafe.Pointer(&ticks[0]))
    cLen := C.size_t(len(ticks))

    // Use runtime.SetCgoWolfmark for callback registration
    runtime.LockOSThread()

    ret := C.process_ticks_async(
        cTicks,
        cLen,
        C.TickResultCallback(C.tick_result_callback_trampoline),
        unsafe.Pointer(collector),
    )

    if ret != 0 {
        return nil, C.GoString(C.ticker_error())
    }

    <-collector.done
    return collector.results, collector.err
}

//export tick_result_callback_trampoline
func tick_result_callback_trampoline(r *C.tick_result, ctx unsafe.Pointer) {
    collector := (*resultCollector)(ctx)

    // CRITICAL: Copy data into Go-owned memory before any C cleanup
    result := TickResult{
        Timestamp: int64(r.ts),
        Price:     float64(r.price),
        Status:    int(r.status),
    }

    collector.mu.Lock()
    collector.results = append(collector.results, result)
    collector.mu.Unlock()
}
