```go
// worker_pool.go - Worker pool with batch processing
package main

import (
    "context"
    "errors"
    "fmt"
    "sync"
    "sync/atomic"
)

type BatchResult struct {
    BatchID int
    Results []TickResult
    Err     error
}

type WorkerPool struct {
    workers    int
    resultCh   chan BatchResult
    wg         sync.WaitGroup
    ctx        context.Context
    cancel     context.CancelFunc
}

func NewWorkerPool(workers int, bufferSize int) *WorkerPool {
    ctx, cancel := context.WithCancel(context.Background())
    return &WorkerPool{
        workers:  workers,
        resultCh: make(chan BatchResult, bufferSize),
        ctx:      ctx,
        cancel:   cancel,
    }
}

func (wp *WorkerPool) ProcessBatches(batches [][]Tick) ([]TickResult, error) {
    var totalResults []TickResult
    var wg sync.WaitGroup
    var errCount int32

    for i, batch := range batches {
        select {
        case <-wp.ctx.Done():
            return totalResults, wp.ctx.Err()
        default:
        }

        wg.Add(1)
        go func(batchID int, ticks []Tick) {
            defer wg.Done()

            results, err := ProcessTicks(ticks)
            if err != nil {
                atomic.AddInt32(&errCount, 1)
                wp.resultCh <- BatchResult{
                    BatchID: batchID,
                    Err:     err,
                }
                return
            }

            wp.resultCh <- BatchResult{
                BatchID: batchID,
                Results: results,
            }
        }(i, batch)
    }

    go func() {
        wg.Wait()
        close(wp.resultCh)
    }()

    for result := range wp.resultCh {
        if result.Err != nil {
            return totalResults, fmt.Errorf("batch %d failed: %w", result.BatchID, result.Err)
        }
        totalResults = append(totalResults, result.Results...)
    }

    if errCount > 0 {
        return totalResults, fmt.Errorf("%d batches failed", errCount)
    }

    return totalResults, nil
}

func (wp *WorkerPool) Shutdown() {
    wp.cancel()
    wp.wg.Wait()
}

// Example usage
func main() {
    // Create sample batches
    batches := [][]Tick{
        {{Timestamp: 1000, Price: 100.0}, {Timestamp: 1001, Price: 101.0}},
        {{Timestamp: 1002, Price: 102.0}, {Timestamp: 1003, Price: 103.0}},
    }

    pool := NewWorkerPool(4, len(batches))
    results, err := pool.ProcessBatches(batches)
    if err != nil {
        fmt.Printf("Error: %v\n", err)
        return
    }

    fmt.Printf("Processed %d results\n", len(results))
    pool.Shutdown()
}
```

