package main

/*
#cgo CFLAGS: -I.
#cgo LDFLAGS: -L. -lverify_blocks
#include "verify_blocks.h"
*/
import "C"
import (
    "runtime/cgo"
    "unsafe"
)

func VerifyBlocks(blocks [][]byte, publicKey []byte) (string, error) {
    n := len(blocks)
    if n == 0 {
        return "[]", nil
    }

    blockPtrs := make([]*C.uint8_t, n)
    blockLens := make([]C.size_t, n)
    for i, b := range blocks {
        blockPtrs[i] = (*C.uint8_t)(C.CBytes(b))
        blockLens[i] = C.size_t(len(b))
    }
    defer func() {
        for _, p := range blockPtrs {
            C.free(unsafe.Pointer(p))
        }
    }()

    pubKeyPtr := (*C.uint8_t)(unsafe.Pointer(&publicKey[0]))
    pubKeyLen := C.size_t(len(publicKey))

    var outJson *C.char
    ret := C.verify_blocks(&blockPtrs[0], &blockLens[0], C.size_t(n),
                           pubKeyPtr, pubKeyLen, &outJson)
    if ret != 0 || outJson == nil {
        return "", cgo.Handle(0)
    }
    defer C.free(unsafe.Pointer(outJson))

    return C.GoString(outJson), nil
}
```

**Go Program with Worker Pool (main.go):**
```go
package main

import (
    "crypto/sha256"
    "encoding/json"
    "fmt"
    "sync"
)

type Result struct {
    Index int  `json:"idx"`
    Valid bool `json:"valid"`
}

func main() {
    blocks := [][][]byte{
        {[]byte("data1"), []byte("data2")},
        {[]byte("data3")},
    }
    publicKey := []byte("test-key")
    numWorkers := 4

    type blockJob struct {
        block    []byte
        index    int
        resultCh chan Result
    }
    jobCh := make(chan blockJob, 100)
    var wg sync.WaitGroup

    for i := 0; i < numWorkers; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for job := range jobCh {
                jsonStr, err := VerifyBlocks([][]byte{job.block}, publicKey)
                var valid bool
                if err == nil {
                    var results []Result
                    if err := json.Unmarshal([]byte(jsonStr), &results); err == nil {
                        valid = results[0].Valid
                    }
                }
                job.resultCh <- Result{Index: job.index, Valid: valid}
            }
        }()
    }

    resultCh := make(chan Result, len(blocks))
    for i, blockGroup := range blocks {
        for _, block := range blockGroup {
            jobCh <- blockJob{block: block, index: i, resultCh: resultCh}
        }
    }
    close(jobCh)
    go func() {
        wg.Wait()
        close(resultCh)
    }()

    var results []Result
    for r := range resultCh {
        results = append(results, r)
    }

    flagBytes := make([]byte, len(results))
    for i, r := range results {
        if r.Valid {
            flagBytes[i] = 1
        }
    }
    batchHash := sha256.Sum256(flagBytes)

    fmt.Printf("Results: %v\nBatch SHA-256: %x\n", results, batchHash)
}
```

## Key Implementation Details

1. **Memory Safety**: Always copy Go slice data via `C.CBytes()` and free in deferred cleanup to prevent GC interference.
2. **Error Propagation**: Use return values and channel-based result collection to surface failures from workers.
3. **Thread Safety**: Worker pool processes jobs concurrently; result channel is buffered to prevent blocking.
4. **Batch Hashing**: Collect all validity flags into a byte slice, then compute SHA-256 to produce a deterministic batch commitment.

