```c
// minimal impl: writes [a,b,...] or -1 if too small
#include <stdint.h>
#include <stdio.h>

int ints_to_json(const int32_t* data, size_t n, char* out, size_t out_len) {
    int needed = snprintf(NULL, 0, "[%d", data[0]);
    for (size_t i = 1; i < n; i++) {
        needed += snprintf(NULL, 0, ",%d", data[i]);
    }
    needed += 1; // closing bracket
    if ((size_t)needed > out_len) return -1;
    char *ptr = out;
    ptr += sprintf(ptr, "[%d", data[0]);
    for (size_t i = 1; i < n; i++) {
        ptr += sprintf(ptr, ",%d", data[i]);
    }
    *ptr = ']';
    return 0;
}
```

