## Streaming Worker Pool

```go
func StreamSignBatch(messages <-chan string, batchSize int) (map[string]string, []byte, error) {
    results := make(chan map[string]string)
    errors := make(chan error, 1)

    var wg sync.WaitGroup
    for i := 0; i < runtime.NumCPU(); i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            batch := []string{}
            for msg := range messages {
                batch = append(batch, msg)
                if len(batch) == batchSize {
                    if sigs, err := SignBatch(batch); err != nil {
                        errors <- err
                        return
                    } else {
                        results <- parseSigs(sigs)
                    }
                    batch = batch[:0]
                }
            }
        }()
    }

    go func() {
        wg.Wait()
        close(results)
    }()

    allSigs := map[string]string{}
    for batch := range results {
        for k, v := range batch {
            allSigs[k] = v
        }
    }

    batchHash := sha256.Sum256(concatSignatures(allSigs))
    return allSigs, batchHash[:], nil
}
```

