questions.explanation:
## Why This Is Asked
Tests CGO memory ownership, cross-language data transfer, and safe concurrency with a real C API that allocates memory.

## Key Concepts
- Ownership transfer from C to Go
- Copying vs zero-copy boundaries
- Proper freeing of C-allocated memory
- Concurrency: multiple CGO calls in parallel

## Code Example
```c
// header.h
int histogram(const double* data, size_t n, unsigned int bins, unsigned int** counts, double** edges);
void free_histogram(unsigned int* counts, double* edges);
```
```c
// impl.c
#include <stdlib.h>
#include "header.h"

int histogram(const double* data, size_t n, unsigned int bins, unsigned int** counts, double** edges) {
  if (!data || n == 0 || bins == 0) return -1;
  *counts = (unsigned int*)malloc(bins * sizeof(unsigned int));
  *edges  = (double*)malloc((bins + 1) * sizeof(double));
  if (!*counts || !*edges) { free(*counts); free(*edges); return -1; }
  // simple uniform histogram
  for (unsigned int i = 0; i < bins; ++i) (*counts)[i] = 0;
  double minv = data[0], maxv = data[0];
  for (size_t i = 1; i < n; ++i) { if (data[i] < minv) minv = data[i]; if (data[i] > maxv) maxv = data[i]; }
  double width = (maxv - minv) / bins;
  for (unsigned int i = 0; i <= bins; ++i) (*edges)[i] = minv + i * width;
  for (size_t i = 0; i < n; ++i) {
    unsigned int idx = (unsigned int)((data[i] - minv) / width);
    if (idx >= bins) idx = bins - 1;
    (*counts)[idx]++;
  }
  return 0;
}

void free_histogram(unsigned int* counts, double* edges) {
  free(counts);
  free(edges);
}
```
```go
// histogram.go
package histogram
/*
#include "header.h"
*/
import "C"
import (
  "errors"
  "unsafe"
)

type Histogram struct {
  Counts []uint32
  Edges  []float64
}

func ComputeHistogram(data []float64, bins int) (Histogram, error) {
  if len(data) == 0 || bins <= 0 {
    return Histogram{}, errors.New("invalid input")
  }
  var counts *C.uint32_t
  var edges *C.double
  // Because Go cannot allocate C memory directly for this pattern, use cgo calls
  cCounts := (**C.uint32_t)(unsafe.Pointer(&counts))
  cEdges := ((**C.double)(unsafe.Pointer(&edges)))
  n := C.size_t(len(data))
  res := C.histogram((*C.double)(&data[0]), n, C.uint(bins), counts, edges)
  if res != 0 {
    return Histogram{}, errors.New("histogram failed in C")
  }
  // Copy to Go slices
  goCounts := make([]uint32, bins)
  goEdges := make([]float64, bins+1)
  // Copy memory (unsafe)
  for i := 0; i < bins; i++ {
    goCounts[i] = uint32(*(*uint32)(unsafe.Pointer(uintptr(unsafe.Pointer(counts)) + uintptr(i)*unsafe.Sizeof(uint32(0)))))
  }
  for i := 0; i <= bins; i++ {
    goEdges[i] = *(*float64)(unsafe.Pointer(uintptr(unsafe.Pointer(edges)) + uintptr(i)*unsafe.Sizeof(float64(0))))
  }
  C.free_histogram(counts, edges)
  return Histogram{Counts: goCounts, Edges: goEdges}, nil
}
```

## Follow-up Questions
- How would you handle extremely large datasets where copying to Go becomes a bottleneck?
- What happens if histogram fails mid-way and partial data was written?
- How to adapt to 64-bit builds or different allocators?

## Why This Is Asked
Tests memory ownership across the CGO boundary and safe deallocation. Tokenization is simple in C but memory mgmt is error-prone; the Go binding must copy results and free C memory in all paths, including errors. Running two tokenizations concurrently checks thread safety of the wrapper.

## Key Concepts
- CGO memory ownership and malloc/free
- Converting C arrays of strings to Go slices
- Error propagation and nil checks
- Concurrency safety with CGO calls

## Code Example
```c
// header (tokenize.h)
char** tokenize(const char* input, size_t* count);
```

```c
// minimal implementation (tokenize.c)
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

char** tokenize(const char* input, size_t* count) {
  if (!input) { *count = 0; return NULL; }
  // simple two-pass: count tokens
  size_t n = 0; const char* p = input; while (*p) { while (isspace((unsigned char)*p)) p++; if (*p) { n++; while (*p && !isspace((unsigned char)*p)) p++; } }
  char** tokens = (char**)malloc(n * sizeof(char*));
  if (!tokens) { *count = 0; return NULL; }
  size_t idx = 0; p = input; while (*p) {
    while (*p && isspace((unsigned char)*p)) p++;
    if (!*p) break;
    const char* start = p; while (*p && !isspace((unsigned char)*p)) p++;
    size_t len = p - start;
    tokens[idx] = (char*)malloc(len + 1);
    memcpy(tokens[idx], start, len);
    tokens[idx][len] = '\0';
    idx++;
  }
  *count = idx;
  return tokens;
}
```

```go
// Go binding sketch (tokenize.go)
package main

/*
#include <stdlib.h>
#include "tokenize.h"
*/
import "C"
import (
  "errors"
  "unsafe"
)

func Tokenize(text string) ([]string, error) {
  cstr := C.CString(text)
  defer C.free(unsafe.Pointer(cstr))
  var count C.size_t
  tokens := C.tokenize(cstr, &count)
  if tokens == nil {
    return nil, errors.New("tokenize failed")
  }
  // copy to Go and free C memory
  result := make([]string, int(count))
  for i := 0; i < int(count); i++ {
    s := C.GoString(tokens[i])
    result[i] = s
    C.free(unsafe.Pointer(tokens[i]))
  }
  C.free(unsafe.Pointer(tokens))
  return result, nil
}
```

