## Why This Is Asked
Assess the ability to design CGO bridges that handle asynchronous C APIs with Go callbacks and memory ownership, implement a streaming worker pattern, and manage thread-safety and resource cleanup across language boundaries.

## Key Concepts
- CGO callbacks and go.Handle bridging
- Memory ownership and lifecycle management across the C/Go boundary
- Asynchronous coordination and backpressure in mixed-language code
- Deterministic cleanup in Go/C interop
- Concurrency patterns in Go worker pools

## Code Example
```c
// digest_async.h
typedef void (*OnBlock)(size_t idx, const char* digest_hex, void* user);
typedef void (*OnComplete)(const char* out_json, void* user);

int digest_batch_async(
    const uint8_t** blocks,
    size_t n,
    size_t block_len,
    OnBlock on_block,
    OnComplete on_complete,
    void* user
);
```

```c
// digest_async.c
#include "digest_async.h"
#include <openssl/sha.h>
#include <stdlib.h>
#include <string.h>

static void SHA256_hex(const uint8_t* data, size_t len, char* out) {
    unsigned char hash[SHA256_DIGEST_LENGTH];
    SHA256(data, len, hash);
    for (int i = 0; i < SHA256_DIGEST_LENGTH; i++)
        sprintf(out + i * 2, "%02x", hash[i]);
}

static int build_result_json(
    const uint8_t** blocks, size_t n, size_t block_len,
    char** out_json
) {
    size_t buf_size = 64 * n + 32;
    char* buf = malloc(buf_size);
    if (!buf) return -1;

    char* p = buf;
    p += sprintf(p, "{\"results\":[");
    for (size_t i = 0; i < n; i++) {
        char hex[SHA256_DIGEST_LENGTH * 2 + 1];
        SHA256_hex(blocks[i], block_len, hex);
        p += sprintf(p, "{\"index\":%zu,\"digest\":\"%s\"},", i, hex);
    }
    p--; *p = ']';
    p += sprintf(p, "}");
    *out_json = buf;
    return 0;
}

int digest_batch_async(
    const uint8_t** blocks, size_t n, size_t block_len,
    OnBlock on_block, OnComplete on_complete, void* user
) {
    char hex[SHA256_DIGEST_LENGTH * 2 + 1];
    for (size_t i = 0; i < n; i++) {
        SHA256_hex(blocks[i], block_len, hex);
        on_block(i, hex, user);
    }

    char* json = NULL;
    int ret = build_result_json(blocks, n, block_len, &json);
    if (ret == 0) {
        on_complete(json, user);
        free(json);
    }
    return ret;
}
```

```go
// digest_cgo.go
package main

/*
#cgo CFLAGS: -I.
#cgo LDFLAGS: -lcrypto
#include "digest_async.h"
#include <stdlib.h>

typedef struct {
    void* handle;
} GoCallbackContext;

extern void goOnBlock(size_t idx, const char* digest_hex, void* user);
extern void goOnComplete(const char* out_json, void* user);
*/
import "C"

import (
    "encoding/json"
    "fmt"
    "runtime"
    "sync"
)

type blockResult struct {
    Index  int    `json:"index"`
    Digest string `json:"digest"`
}

type batchResult struct {
    Results []blockResult `json:"results"`
}

var (
    mu       sync.Mutex
    callback = struct {
        perBlock []string
        batch    string
        done     chan struct{}
        err      error
    }{}
    registry = make(map[uint64]chan struct{})
)

export goOnBlock := func(idx C.size_t, digestHex *C.char, user unsafe.Pointer) {
    mu.Lock()
    defer mu.Unlock()
    if idx >= C.size_t(len(callback.perBlock)) {
        callback.perBlock = append(callback.perBlock, C.GoString(digestHex))
    }
}

export goOnComplete := func(jsonStr *C.char, user unsafe.Pointer) {
    defer C.free(unsafe.Pointer(jsonStr))
    mu.Lock()
    defer mu.Unlock()
    callback.batch = C.GoString(jsonStr)
    close(callback.done)
}

func DigestBatchAsync(blocks [][]byte) (perBlock []string, batch string, err error) {
    mu.Lock()
    callback.perBlock = make([]string, 0, len(blocks))
    callback.batch = ""
    callback.done = make(chan struct{})
    mu.Unlock()

    cBlocks := make([]*C.uint8_t, len(blocks))
    for i, b := range blocks {
        cBlocks[i] = (*C.uint8_t)(C.CBytes(b))
    }
    defer func() {
        for _, p := range cBlocks {
            C.free(unsafe.Pointer(p))
        }
    }()

    n := C.size_t(len(blocks))
    blockLen := C.size_t(0)
    if n > 0 {
        blockLen = C.size_t(len(blocks[0]))
    }

    ret := C.digest_batch_async(
        (**C.uint8_t)(&cBlocks[0]),
        n,
        blockLen,
        C.OnBlock(C.goOnBlock),
        C.OnComplete(C.goOnComplete),
        nil,
    )

    select {
    case <-callback.done:
    }

    mu.Lock()
    defer mu.Unlock()
    return callback.perBlock, callback.batch, nil
}

func main() {
    blocks := [][]byte{
        []byte("block1"),
        []byte("block2"),
        []byte("block3"),
    }

    perBlock, batch, err := DigestBatchAsync(blocks)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }

    fmt.Println("Per-block digests:", perBlock)
    fmt.Println("Batch JSON:", batch)
}
```

## What to Look For
- Correct use of CGO `export` directives and callback registration
- Proper memory lifecycle: C allocations copied to Go then freed immediately
- Thread-safety via mutexes protecting shared callback state
