## Plan

Implement a C wrapper function `sort_strings` that accepts input strings, allocates the output array with `malloc`, and returns sorted results. In the Go binding, export a Go comparator as a C callback using `//export`, store the comparator in a global map keyed by an integer handle, and pass this handle to C. On the C side, retrieve the comparator via the handle and invoke it during sorting.

## 1) Header and Minimal C Implementation

**sort_strings.h:**
```c
#ifndef SORT_STRINGS_H
#define SORT_STRINGS_H

#include <stddef.h>

int sort_strings(const char** in, size_t n, char*** out_sorted, int comparator_handle);

#endif
```

**sort_strings.c:**
```c
#include <stdlib.h>
#include <string.h>

extern int go_comparator(const char* a, const char* b, int handle);

static int cmp_wrapper(const void* a, const void* b, void* handle) {
    const char* sa = *(const char**)a;
    const char* sb = *(const char**)b;
    return go_comparator(sa, sb, *(int*)handle);
}

int sort_strings(const char** in, size_t n, char*** out_sorted, int comparator_handle) {
    if (!in || !out_sorted || n == 0) {
        return -1;
    }

    *out_sorted = malloc(n * sizeof(char*));
    if (!*out_sorted) {
        return -1;
    }

    for (size_t i = 0; i < n; i++) {
        (*out_sorted)[i] = (char*)in[i];
    }

    qsort_r(*out_sorted, n, sizeof(char*), cmp_wrapper, &comparator_handle);
    return 0;
}
```

## 2) Go Binding

```go
package sortbridge

/*
#cgo CFLAGS: -I.
#cgo LDFLAGS: -L. -lsort_strings

#include "sort_strings.h"
#include <stdlib.h>

extern int goComparator(const char* a, const char* b, int handle);

static int callGoComparator(const void* a, const void* b, int handle) {
    return goComparator(*(const char**)a, *(const char**)b, handle);
}

static int csort_strings(const char** in, size_t n, char*** out, int handle) {
    return sort_strings(in, n, out, handle);
}
*/
import "C"

import (
    "fmt"
    "sync"
    "unsafe"
)

var (
    comparatorMu  sync.RWMutex
    comparatorMap = make(map[int]func(string, string) int)
    nextHandle    int
)

//export goComparator
func goComparator(a *C.char, b *C.char, handle C.int) C.int {
    comparatorMu.RLock()
    cmp, ok := comparatorMap[int(handle)]
    comparatorMu.RUnlock()

    if !ok {
        return 0
    }
    return C.int(cmp(C.GoString(a), C.GoString(b)))
}

func SortStrings(vals []string, cmp func(string, string) int) ([]string, error) {
    if len(vals) == 0 {
        return nil, nil
    }

    handle := func() int {
        comparatorMu.Lock()
        defer comparatorMu.Unlock()
        h := nextHandle
        nextHandle++
        comparatorMap[h] = cmp
        return h
    }()

    defer func() {
        comparatorMu.Lock()
        delete(comparatorMap, handle)
        comparatorMu.Unlock()
    }()

    cVals := make([]*C.char, len(vals))
    for i, v := range vals {
        cVals[i] = C.CString(v)
        defer C.free(unsafe.Pointer(cVals[i]))
    }

    var cOut *C.char
    ret := C.sort_strings((**C.char)(unsafe.Pointer(&cVals[0])), C.size_t(len(vals)), &cOut, C.int(handle))
    if ret != 0 {
        return nil, fmt.Errorf("sort failed with status %d", ret)
    }

    defer C.free(unsafe.Pointer(cOut))

    result := make([]string, len(vals))
    ptr := uintptr(unsafe.Pointer(cOut))
    for i := range vals {
        result[i] = C.GoString(*(**C.char)(unsafe.Pointer(ptr)))
        ptr += unsafe.Sizeof(cOut)
    }

    return result, nil
}
```

## 3) Go Worker Pool with Streaming and JSON Output

```go
package main

import (
    "encoding/json"
    "fmt"
    "os"
    "strings"
    "sync"
)

type SortRequest struct {
    BatchID int
    Batch   []string
}

type BatchResult struct {
    BatchID int
    Sorted  []string
    Indices []int
    Err     error
}

func worker(jobs <-chan SortRequest, results chan<- BatchResult) {
    for req := range jobs {
        sorted, err := sortbridge.SortStrings(req.Batch, strings.Compare)
        if err != nil {
            results <- BatchResult{BatchID: req.BatchID, Err: err}
            continue
        }

        posMap := make(map[string][]int, len(req.Batch))
        for i, v := range req.Batch {
            posMap[v] = append(posMap[v], i)
        }

        indices := make([]int, len(sorted))
        for i, v := range sorted {
            indices[i] = posMap[v][0]
            posMap[v] = posMap[v][1:]
        }

        results <- BatchResult{
            BatchID: req.BatchID,
            Sorted:  sorted,
            Indices: indices,
        }
    }
}

func StreamSort(batches [][]string, numWorkers int) ([]BatchResult, error) {
    jobs := make(chan SortRequest, numWorkers)
    results := make(chan BatchResult, len(batches))

    var wg sync.WaitGroup
    for i := 0; i < numWorkers; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            worker(jobs, results)
        }()
    }

    go func() {
        wg.Wait()
        close(results)
    }()

    for i, batch := range batches {
        jobs <- SortRequest{BatchID: i, Batch: batch}
    }
    close(jobs)

    var allResults []BatchResult
    var lastErr error
    for r := range results {
        if r.Err != nil && lastErr == nil {
            lastErr = r.Err
        }
        allResults = append(allResults, r)
    }

    return allResults, lastErr
}

func main() {
    batches := [][]string{
        {"banana", "apple", "cherry"},
        {"zebra", "mango", "grape"},
    }

    results, err := StreamSort(batches, 4)
    if err != nil {
        fmt.Fprintf(os.Stderr, "Error: %v\n", err)
        os.Exit(1)
    }

    output := make([]map[string]interface{}, len(results))
    for _, r := range results {
        output[r.BatchID] = map[string]interface{}{
            "sorted":  r.Sorted,
            "indices": r.Indices,
        }
    }

    enc := json.NewEncoder(os.Stdout)
    enc.SetIndent("", "  ")
    if err := enc.Encode(output); err != nil {
        fmt.Fprintf(os.Stderr, "JSON encode error: %v\n", err)
        os.Exit(1)
    }
}
```

## C Header (tokenizer.h)

```c
#ifndef TOKENIZER_H
#define TOKENIZER_H

typedef struct Token {
    char* text;
    int type;
} Token;

enum TokenType {
    IDENT = 0,
    NUM = 1
};

Token* next_token(const char* input, size_t len, int* produced, int* eof);
void free_token(Token* tok);

#endif
```

## C Implementation (tokenizer.c)

```c
#include <stdlib.h>
#include <string.h>
#include <ctype.h>
#include "tokenizer.h"

static int get_token_type(char c) {
    return isalpha(c) ? IDENT : NUM;
}

static size_t token_length(const char* start, size_t max_len) {
    if (max_len == 0) return 0;
    int type = get_token_type(*start);
    size_t len = 1;
    while (len < max_len && get_token_type(start[len]) == type) {
        len++;
    }
    return len;
}

Token* next_token(const char* input, size_t len, int* produced, int* eof) {
    *produced = 0;
    *eof = 0;

    size_t i = 0;
    while (i < len && isspace((unsigned char)input[i])) i++;
    if (i >= len) {
        *eof = 1;
        return NULL;
    }

    size_t tok_len = token_length(input + i, len - i);
    Token* tok = malloc(sizeof(Token));
    if (!tok) return NULL;

    tok->text = malloc(tok_len + 1);
    if (!tok->text) {
        free(tok);
        return NULL;
    }

    memcpy(tok->text, input + i, tok_len);
    tok->text[tok_len] = '\0';
    tok->type = get_token_type(input[i]);
    *produced = (int)(i + tok_len);

    return tok;
}

void free_token(Token* tok) {
    if (tok) {
        free(tok->text);
        free(tok);
    }
}
```

## Go Binding (tokenizer.go)

```go
package tokenizer

/*
#cgo CFLAGS: -I.
#cgo LDFLAGS: -L. -ltokenizer
#include "tokenizer.h"
*/
import "C"
import "unsafe"

type TokenType int

const (
	IDENT TokenType = 0
	NUM   TokenType = 1
)

type Token struct {
	Text string
	Type TokenType
}

func StreamTokens(chunks <-chan string) (<-chan Token, <-chan error) {
	tokens := make(chan Token)
	errs := make(chan error, 1)

	go func() {
		defer close(tokens)
		defer close(errs)

		offset := 0
		for chunk := range chunks {
			cStr := C.CString(chunk)
			defer C.free(unsafe.Pointer(cStr))
			offset = 0

			for {
				remaining := chunk[offset:]
				var produced C.int
				var eof C.int

				tok := C.next_token(cStr, C.size_t(len(chunk)), &produced, &eof)

				if tok == nil {
					break
				}

				tokens <- Token{
					Text: C.GoString(tok.text),
					Type: TokenType(tok._type),
				}
				C.free_token(tok)

				offset = int(produced)
				if offset >= len(chunk) {
					break
				}
			}
		}
	}()

	return tokens, errs
}
```

## Go Program with Parallel Streams (main.go)

```go
package main

import (
	"fmt"
	"sync"

	"github.com/tokenizer"
)

func main() {
	chunks1 := make(chan string, 10)
	chunks2 := make(chan string, 10)

	var wg sync.WaitGroup
	wg.Add(2)

	go func() {
		defer wg.Done()
		for _, chunk := range []string{"hello 123 world", " 456 test"} {
			chunks1 <- chunk
		}
		close(chunks1)
	}()

	go func() {
		defer wg.Done()
		for _, chunk := range []string{"abc 42 xyz", " 789 done"} {
			chunks2 <- chunk
		}
		close(chunks2)
	}()

	tokens1, _ := tokenizer.StreamTokens(chunks1)
	tokens2, _ := tokenizer.StreamTokens(chunks2)

	var outWg sync.WaitGroup
	outWg.Add(2)

	go func() {
		defer outWg.Done()
		for tok := range tokens1 {
			fmt.Printf("Stream1: %s (type %d)\n", tok.Text, tok.Type)
		}
	}()

	go func() {
		defer outWg.Done()
		for tok := range tokens2 {
			fmt.Printf("Stream2: %s (type %d)\n", tok.Text, tok.Type)
		}
	}()

	wg.Wait()
	outWg.Wait()
}
```

