```c
#include <stdlib.h>
#include <string.h>
#include <tokenizer.h>

int tokenize_line(const char* line, char*** tokens, size_t* n){
  if(!line) return -1;
  const char* p = line;
  size_t cap = 8, i = 0;
  char** toks = (char**)malloc(cap*sizeof(char*));
  while(*p){
    while(*p==' ') p++;
    if(!*p) break;
    const char* start = p;
    int inq = 0;
    while(*p){
      if(*p=='"') inq = !inq;
      else if(*p==' ' && !inq) break;
      p++;
    }
    size_t len = p-start;
    char* t = (char*)malloc(len+1);
    memcpy(t, start, len);
    t[len] = '\0';
    if(i==cap){ cap*=2; toks=(char**)realloc(toks, cap*sizeof(char*)); }
    toks[i++] = t;
  }
  *tokens = toks; *n = i; return 0;
}

void free_tokens(char** tokens, size_t n){
  if(!tokens) return; for(size_t i=0;i<n;i++){ free(tokens[i]); } free(tokens);
}
```
