  "errors"
  "unsafe"
)

func TokenizeLine(line string) ([]string, error) {
  cLine := C.CString(line)
  defer C.free(unsafe.Pointer(cLine))
  var cTokens **C.char
  var n C.size_t
  if code := C.tokenize_line(cLine, &cTokens, &n); code != 0 {
    return nil, errors.New("tokenization failed")
  }
  count := int(n)
  toks := make([]string, 0, count)
  slice := (*[1<<30]*C.char)(unsafe.Pointer(cTokens))[:count:count]
  for _, cstr := range slice {
    toks = append(toks, C.GoString(cstr))
  }
  C.free_tokens(cTokens, n)
  return toks, nil
}
