Build a CGO wrapper around the opaque C kv_store. Expose a type Store with Put(string, string) error, Get(string) (string, error), and Close() error. Get must return a fresh Go string via C.GoString, and kv_store must be freed exactly once.

```go
package kvstore

// #include "kv.h"
import "C"
import (
	"errors"
	"sync"
	"unsafe"
)

type Store struct {
	handle *C.kv_store
}

func New() (*Store, error) {
	h := C.kv_create()
	if h == nil {
		return nil, errors.New("failed to create store")
	}
	return &Store{handle: h}, nil
}

func (s *Store) Put(key, value string) error {
	ckey := C.CString(key)
	cvalue := C.CString(value)
	defer func() {
		C.free(unsafe.Pointer(ckey))
		C.free(unsafe.Pointer(cvalue))
	}()
	C.kv_put(s.handle, ckey, cvalue)
	return nil
}

func (s *Store) Get(key string) (string, error) {
	ckey := C.CString(key)
	defer C.free(unsafe.Pointer(ckey))

	cstr := C.kv_get(s.handle, ckey)
	if cstr == nil {
		return "", nil
	}
	defer C.free(unsafe.Pointer(cstr))
	return C.GoString(cstr), nil
}

func (s *Store) Close() error {
	C.kv_free(s.handle)
	s.handle = nil
	return nil
}
```

