## Go Worker Pool with Streaming and SHA-256

```go
package main

import (
    "crypto/sha256"
    "encoding/hex"
    "encoding/json"
    "fmt"
    "sync"
)

type RecordResult struct {
    Index      int             `json:"index"`
    Valid      bool            `json:"valid"`
    Normalized json.RawMessage `json:"normalized,omitempty"`
    Error      string          `json:"error,omitempty"`
}

func processBatch(records [][]byte, schema string) ([]RecordResult, string, error) {
    jsonResult, err := ValidateWithSchema(records, schema)
    if err != nil {
        return nil, "", err
    }

    var results []RecordResult
    json.Unmarshal([]byte(jsonResult), &results)

    h := sha256.New()
    for _, r := range results {
        h.Write([]byte(fmt.Sprintf("%d:%v", r.Index, r.Valid)))
    }
    checksum := hex.EncodeToString(h.Sum(nil))

    return results, checksum, nil
}

type WorkerPool struct {
    workers   int
    schema    string
    recordCh  chan [][]byte
    resultCh  chan []RecordResult
    checksumCh chan string
    wg        sync.WaitGroup
}

func NewWorkerPool(workers int, schema string) *WorkerPool {
    return &WorkerPool{
        workers:    workers,
        schema:     schema,
        recordCh:   make(chan [][]byte, workers*2),
        resultCh:   make(chan []RecordResult, workers*2),
        checksumCh: make(chan string, workers*2),
    }
}

func (wp *WorkerPool) Start() {
    for i := 0; i < wp.workers; i++ {
        wp.wg.Add(1)
        go func() {
            defer wp.wg.Done()
            for batch := range wp.recordCh {
                results, checksum, err := processBatch(batch, wp.schema)
                if err == nil {
                    wp.resultCh <- results
                    wp.checksumCh <- checksum
                }
            }
        }()
    }
}

func (wp *WorkerPool) Submit(batch [][]byte) {
    wp.recordCh <- batch
}

func (wp *WorkerPool) Shutdown() {
    close(wp.recordCh)
    wp.wg.Wait()
    close(wp.resultCh)
    close(wp.checksumCh)
}

func main() {
    schema := `{"type":"object","properties":{"id":{"type":"string"}}}`
    pool := NewWorkerPool(4, schema)
    pool.Start()

    // Stream batches
    // pool.Submit(batch)

    pool.Shutdown()
}
```

