struct Config { char* data; };
Config* config_new(const char* json){ if(!json) return NULL; Config* c=malloc(sizeof(Config)); c->data=strdup(json); return c; }
const char* config_to_json(const Config* cfg){ return cfg? cfg->data: NULL; }
