// binding.go
package main

// #include "config.h"
// #cgo CFLAGS: -I.
import "C"
import (
  "errors"
  "unsafe"
)

type ConfigHandle struct{ ptr *C.Config }

func CreateConfig(json string) (*ConfigHandle, error){ cstr := C.CString(json); defer C.free(unsafe.Pointer(cstr)); cfg := C.config_new(cstr); if cfg == nil { return nil, errors.New("config creation failed") }; return &ConfigHandle{ptr: cfg}, nil }

func ConfigToJSON(h *ConfigHandle) (string, error){ if h==nil || h.ptr==nil { return "", errors.New("nil handle") }
  cstr := C.config_to_json(h.ptr); if cstr == nil { return "", nil }
  s := C.GoString(cstr); C.free(unsafe.Pointer((*C.char)(unsafe.Pointer(cstr))))
  return s, nil
}

func (h *ConfigHandle) Close() { if h!=nil && h.ptr!=nil { C.config_free(h.ptr); h.ptr = nil }
