```c
// tls.c
#include "tls.h"
#include <stdlib.h>
static thread_local uint8_t* cache = NULL;
static thread_local size_t cache_size = 0;

void transform_tls(const uint8_t* in, size_t n, uint8_t* out, size_t* out_n) {
    // Initialize per-thread cache if needed
    if (cache == NULL || cache_size < n * 2) {
        free(cache);
        cache_size = n * 2;
        cache = malloc(cache_size);
    }

    // Example transform: simple byte manipulation
    for (size_t i = 0; i < n; i++) {
        cache[i] = in[i] ^ 0xAA;
    }

    // Copy to output
    for (size_t i = 0; i < n; i++) {
        out[i] = cache[i];
    }
    *out_n = n;
}
```

```go
// tls.go
package main

/*
#cgo CFLAGS: -std=c11
#cgo LDFLAGS: -lpthread
#include "tls.h"
*/
import "C"
import (
    "fmt"
    "sync"
    "unsafe"
)

func TransformTLS(src []byte) ([]byte, error) {
    if len(src) == 0 {
        return nil, nil
    }

    out := make([]byte, len(src)*2) // Allocate extra space
    var outN C.size_t

    C.transform_tls(
        (*C.uint8_t)(unsafe.Pointer(&src[0])),
        C.size_t(len(src)),
        (*C.uint8_t)(unsafe.Pointer(&out[0])),
        &outN,
    )

    return out[:outN], nil
}

func main() {
    var wg sync.WaitGroup

    // Concurrent calls
    for i := 0; i < 2; i++ {
        wg.Add(1)
        go func(id int) {
            defer wg.Done()
            data := []byte{byte(id + 1), byte(id + 2), byte(id + 3)}
            result, err := TransformTLS(data)
            if err != nil {
                fmt.Printf("Goroutine %d error: %v\n", id, err)
                return
            }
            fmt.Printf("Goroutine %d: %v -> %v\n", id, data, result)
        }(i)
    }

    wg.Wait()
}
```

